const book: BibleBook = {
  id: 'romans',
  name: 'Romanos',
  englishName: 'Romans',
  testament: 'new',
  chapters: {
    1: [
      { v: 1, en: 'Paul, a servant of Jesus Christ, called to be an apostle, set apart for the Good News of God,', pt: 'Paulo, servo de Jesus Cristo, chamado para ser apóstolo, separado para o evangelho de Deus,' },
      { v: 2, en: 'which he promised before through his prophets in the holy Scriptures,', pt: 'que ele antes havia prometido pelos seus profetas nas santas Escrituras,' },
      { v: 3, en: 'concerning his Son, who was born of the offspring of David according to the flesh,', pt: 'acerca de seu Filho, que nasceu da descendência de Davi segundo a carne,' },
      { v: 4, en: 'who was declared to be the Son of God with power, according to the Spirit of holiness, by the resurrection from the dead, Jesus Christ our Lord,', pt: 'e que com poder foi declarado Filho de Deus segundo o espírito de santidade, pela ressurreição dentre os mortos - Jesus Cristo nosso Senhor,' },
      { v: 5, en: 'through whom we received grace and apostleship, for obedience of faith among all the nations, for his name’s sake;', pt: 'pelo qual recebemos a graça e o apostolado, por amor do seu nome, para a obediência da fé entre todos os gentios,' },
      { v: 6, en: 'among whom you are also called to belong to Jesus Christ;', pt: 'entre os quais sois também vós chamados para serdes de Jesus Cristo;' },
      { v: 7, en: 'to all who are in Rome, beloved of God, called to be saints: Grace to you and peace from God our Father and the Lord Jesus Christ.', pt: 'a todos os que estais em Roma, amados de Deus, chamados para serdes santos: Graça a vós, e paz da parte de Deus nosso Pai, e do Senhor Jesus Cristo.' },
      { v: 8, en: 'First, I thank my God through Jesus Christ for all of you, that your faith is proclaimed throughout the whole world.', pt: 'Primeiramente dou graças ao meu Deus, mediante Jesus Cristo, por todos vós, porque em todo o mundo é anunciada a vossa fé.' },
      { v: 9, en: 'For God is my witness, whom I serve in my spirit in the Good News of his Son, how unceasingly I make mention of you always in my prayers,', pt: 'Pois Deus, a quem sirvo em meu espírito, no evangelho de seu Filho, me é testemunha de como incessantemente faço menção de vós,' },
      { v: 10, en: 'requesting, if by any means now at last I may be prospered by the will of God to come to you.', pt: 'pedindo sempre em minhas orações que, afinal, pela vontade de Deus, se me ofereça boa ocasião para ir ter convosco.' },
      { v: 11, en: 'For I long to see you, that I may impart to you some spiritual gift, to the end that you may be established;', pt: 'Porque desejo muito ver-vos, para vos comunicar algum dom espiritual, a fim de que sejais fortalecidos;' },
      { v: 12, en: 'that is, that I with you may be encouraged in you, each of us by the other’s faith, both yours and mine.', pt: 'isto é, para que juntamente convosco eu seja consolado em vós pela fé mútua, vossa e minha.' },
      { v: 13, en: 'Now I don’t desire to have you unaware, brothers, that I often planned to come to you, and was hindered so far, that I might have some fruit among you also, even as among the rest of the Gentiles.', pt: 'E não quero que ignoreis, irmãos, que muitas vezes propus visitar-vos (mas até agora tenho sido impedido), para conseguir algum fruto entre vós, como também entre os demais gentios.' },
      { v: 14, en: 'I am debtor both to Greeks and to foreigners, both to the wise and to the foolish.', pt: 'Eu sou devedor, tanto a gregos como a bárbaros, tanto a sábios como a ignorantes.' },
      { v: 15, en: 'So, as much as is in me, I am eager to preach the Good News to you also who are in Rome.', pt: 'De modo que, quanto está em mim, estou pronto para anunciar o evangelho também a vós que estais em Roma.' },
      { v: 16, en: 'For I am not ashamed of the Good News of Christ, because it is the power of God for salvation for everyone who believes; for the Jew first, and also for the Greek.', pt: 'Porque não me envergonho do evangelho, pois é o poder de Deus para salvação de todo aquele que crê; primeiro do judeu, e também do grego.' },
      { v: 17, en: 'For in it is revealed God’s righteousness from faith to faith. As it is written, “But the righteous shall live by faith.”', pt: 'Porque no evangelho é revelada, de fé em fé, a justiça de Deus, como está escrito: Mas o justo viverá da fé.' },
      { v: 18, en: 'For the wrath of God is revealed from heaven against all ungodliness and unrighteousness of men, who suppress the truth in unrighteousness,', pt: 'Pois do céu é revelada a ira de Deus contra toda a impiedade e injustiça dos homens que detêm a verdade em injustiça.' },
      { v: 19, en: 'because that which is known of God is revealed in them, for God revealed it to them.', pt: 'Porquanto, o que de Deus se pode conhecer, neles se manifesta, porque Deus lho manifestou.' },
      { v: 20, en: 'For the invisible things of him since the creation of the world are clearly seen, being perceived through the things that are made, even his everlasting power and divinity; that they may be without excuse.', pt: 'Pois os seus atributos invisíveis, o seu eterno poder e divindade, são claramente vistos desde a criação do mundo, sendo percebidos mediante as coisas criadas, de modo que eles são inescusáveis;' },
      { v: 21, en: 'Because, knowing God, they didn’t glorify him as God, neither gave thanks, but became vain in their reasoning, and their senseless heart was darkened.', pt: 'porquanto, tendo conhecido a Deus, contudo não o glorificaram como Deus, nem lhe deram graças, antes nas suas especulações se desvaneceram, e o seu coração insensato se obscureceu.' },
      { v: 22, en: 'Professing themselves to be wise, they became fools,', pt: 'Dizendo-se sábios, tornaram-se estultos,' },
      { v: 23, en: 'and traded the glory of the incorruptible God for the likeness of an image of corruptible man, and of birds, and four-footed animals, and creeping things.', pt: 'e mudaram a glória do Deus incorruptível em semelhança da imagem de homem corruptível, e de aves, e de quadrúpedes, e de répteis.' },
      { v: 24, en: 'Therefore God also gave them up in the lusts of their hearts to uncleanness, that their bodies should be dishonored among themselves;', pt: 'Por isso Deus os entregou, nas concupiscências de seus corações, à imundícia, para serem os seus corpos desonrados entre si;' },
      { v: 25, en: 'who exchanged the truth of God for a lie, and worshiped and served the creature rather than the Creator, who is blessed forever. Amen.', pt: 'pois trocaram a verdade de Deus pela mentira, e adoraram e serviram à criatura antes que ao Criador, que é bendito eternamente. Amém.' },
      { v: 26, en: 'For this reason, God gave them up to vile passions. For their women changed the natural function into that which is against nature.', pt: 'Pelo que Deus os entregou a paixões infames. Porque até as suas mulheres mudaram o uso natural no que é contrário à natureza;' },
      { v: 27, en: 'Likewise also the men, leaving the natural function of the woman, burned in their lust toward one another, men doing what is inappropriate with men, and receiving in themselves the due penalty of their error.', pt: 'semelhantemente, também os varões, deixando o uso natural da mulher, se inflamaram em sua sensualidade uns para como os outros, varão com varão, cometendo torpeza e recebendo em si mesmos a devida recompensa do seu erro.' },
      { v: 28, en: 'Even as they refused to have God in their knowledge, God gave them up to a reprobate mind, to do those things which are not fitting;', pt: 'E assim como eles rejeitaram o conhecimento de Deus, Deus, por sua vez, os entregou a um sentimento depravado, para fazerem coisas que não convêm;' },
      { v: 29, en: 'being filled with all unrighteousness, sexual immorality, wickedness, covetousness, malice; full of envy, murder, strife, deceit, evil habits, secret slanderers,', pt: 'estando cheios de toda a injustiça, malícia, cobiça, maldade; cheios de inveja, homicídio, contenda, dolo, malignidade;' },
      { v: 30, en: 'backbiters, hateful to God, insolent, haughty, boastful, inventors of evil things, disobedient to parents,', pt: 'sendo murmuradores, detratores, aborrecedores de Deus, injuriadores, soberbos, presunçosos, inventores de males, desobedientes ao pais;' },
      { v: 31, en: 'without understanding, covenant breakers, without natural affection, unforgiving, unmerciful;', pt: 'néscios, infiéis nos contratos, sem afeição natural, sem misericórdia;' },
      { v: 32, en: 'who, knowing the ordinance of God, that those who practice such things are worthy of death, not only do the same, but also approve of those who practice them.', pt: 'os quais, conhecendo bem o decreto de Deus, que declara dignos de morte os que tais coisas praticam, não somente as fazem, mas também aprovam os que as praticam.' },
    ],
    2: [
      { v: 1, en: 'Therefore you are without excuse, O man, whoever you are who judge. For in that which you judge another, you condemn yourself. For you who judge practice the same things.', pt: 'Portanto, és inescusável, ó homem, qualquer que sejas, quando julgas, porque te condenas a ti mesmo naquilo em que julgas a outro; pois tu que julgas, praticas o mesmo.' },
      { v: 2, en: 'We know that the judgment of God is according to truth against those who practice such things.', pt: 'E bem sabemos que o juízo de Deus é segundo a verdade, contra os que tais coisas praticam.' },
      { v: 3, en: 'Do you think this, O man who judges those who practice such things, and do the same, that you will escape the judgment of God?', pt: 'E tu, ó homem, que julgas os que praticam tais coisas, cuidas que, fazendo-as tu, escaparás ao juízo de Deus?' },
      { v: 4, en: 'Or do you despise the riches of his goodness, forbearance, and patience, not knowing that the goodness of God leads you to repentance?', pt: 'Ou desprezas tu as riquezas da sua benignidade, e paciência e longanimidade, ignorando que a benignidade de Deus te conduz ao arrependimento?' },
      { v: 5, en: 'But according to your hardness and unrepentant heart you are treasuring up for yourself wrath in the day of wrath, revelation, and of the righteous judgment of God;', pt: 'Mas, segundo a tua dureza e teu coração impenitente, entesouras ira para ti no dia da ira e da revelação do justo juízo de Deus,' },
      { v: 6, en: 'who “will pay back to everyone according to their works:”', pt: 'que retribuirá a cada um segundo as suas obras;' },
      { v: 7, en: 'to those who by perseverance in well-doing seek for glory, honor, and incorruptibility, eternal life;', pt: 'a saber: a vida eterna aos que, com perseverança em favor o bem, procuram glória, e honra e incorrupção;' },
      { v: 8, en: 'but to those who are self-seeking, and don’t obey the truth, but obey unrighteousness, will be wrath and indignation,', pt: 'mas ira e indignação aos que são contenciosos, e desobedientes à iniqüidade;' },
      { v: 9, en: 'oppression and anguish, on every soul of man who does evil, to the Jew first, and also to the Greek.', pt: 'tribulação e angústia sobre a alma de todo homem que pratica o mal, primeiramente do judeu, e também do grego;' },
      { v: 10, en: 'But glory, honor, and peace go to every man who does good, to the Jew first, and also to the Greek.', pt: 'glória, porém, e honra e paz a todo aquele que pratica o bem, primeiramente ao judeu, e também ao grego;' },
      { v: 11, en: 'For there is no partiality with God.', pt: 'pois para com Deus não há acepção de pessoas.' },
      { v: 12, en: 'For as many as have sinned without the law will also perish without the law. As many as have sinned under the law will be judged by the law.', pt: 'Porque todos os que sem lei pecaram, sem lei também perecerão; e todos os que sob a lei pecaram, pela lei serão julgados.' },
      { v: 13, en: 'For it isn’t the hearers of the law who are righteous before God, but the doers of the law will be justified', pt: 'Pois não são justos diante de Deus os que só ouvem a lei; mas serão justificados os que praticam a lei' },
      { v: 14, en: '(for when Gentiles who don’t have the law do by nature the things of the law, these, not having the law, are a law to themselves,', pt: '(porque, quando os gentios, que não têm lei, fazem por natureza as coisas da lei, eles, embora não tendo lei, para si mesmos são lei.' },
      { v: 15, en: 'in that they show the work of the law written in their hearts, their conscience testifying with them, and their thoughts among themselves accusing or else excusing them)', pt: 'pois mostram a obra da lei escrita em seus corações, testificando juntamente a sua consciência e os seus pensamentos, quer acusando-os, quer defendendo-os),' },
      { v: 16, en: 'in the day when God will judge the secrets of men, according to my Good News, by Jesus Christ.', pt: 'no dia em que Deus há de julgar os segredos dos homens, por Cristo Jesus, segundo o meu evangelho.' },
      { v: 17, en: 'Indeed you bear the name of a Jew, and rest on the law, and glory in God,', pt: 'Mas se tu és chamado judeu, e repousas na lei, e te glorias em Deus;' },
      { v: 18, en: 'and know his will, and approve the things that are excellent, being instructed out of the law,', pt: 'e conheces a sua vontade e aprovas as coisas excelentes, sendo instruído na lei;' },
      { v: 19, en: 'and are confident that you yourself are a guide of the blind, a light to those who are in darkness,', pt: 'e confias que és guia dos cegos, luz dos que estão em trevas,' },
      { v: 20, en: 'a corrector of the foolish, a teacher of babies, having in the law the form of knowledge and of the truth.', pt: 'instruidor dos néscios, mestre de crianças, que tens na lei a forma da ciência e da verdade;' },
      { v: 21, en: 'You therefore who teach another, don’t you teach yourself? You who preach that a man shouldn’t steal, do you steal?', pt: 'tu, pois, que ensinas a outrem, não te ensinas a ti mesmo? Tu, que pregas que não se deve furtar, furtas?' },
      { v: 22, en: 'You who say a man shouldn’t commit adultery. Do you commit adultery? You who abhor idols, do you rob temples?', pt: 'Tu, que dizes que não se deve cometer adultério, adultéras? Tu, que abominas os ídolos, roubas os templos?' },
      { v: 23, en: 'You who glory in the law, do you dishonor God by disobeying the law?', pt: 'Tu, que te glorias na lei, desonras a Deus pela transgressão da lei?' },
      { v: 24, en: 'For “the name of God is blasphemed among the Gentiles because of you,” just as it is written.', pt: 'Assim pois, por vossa causa, o nome de Deus é blasfemado entre os gentios, como está escrito.' },
      { v: 25, en: 'For circumcision indeed profits, if you are a doer of the law, but if you are a transgressor of the law, your circumcision has become uncircumcision.', pt: 'Porque a circuncisão é, na verdade, proveitosa, se guardares a lei; mas se tu és transgressor da lei, a tua circuncisão tem-se tornado em incircuncisão.' },
      { v: 26, en: 'If therefore the uncircumcised keep the ordinances of the law, won’t his uncircumcision be accounted as circumcision?', pt: 'Se, pois, a incircuncisão guardar os preceitos da lei, porventura a incircuncisão não será reputada como circuncisão?' },
      { v: 27, en: 'Won’t the uncircumcision which is by nature, if it fulfills the law, judge you, who with the letter and circumcision are a transgressor of the law?', pt: 'E a incircuncisão que por natureza o é, se cumpre a lei, julgará a ti, que com a letra e a circuncisão és transgressor da lei.' },
      { v: 28, en: 'For he is not a Jew who is one outwardly, neither is that circumcision which is outward in the flesh;', pt: 'Porque não é judeu o que o é exteriormente, nem é circuncisão a que o é exteriormente na carne.' },
      { v: 29, en: 'but he is a Jew who is one inwardly, and circumcision is that of the heart, in the spirit not in the letter; whose praise is not from men, but from God.', pt: 'Mas é judeu aquele que o é interiormente, e circuncisão é a do coração, no espírito, e não na letra; cujo louvor não provém dos homens, mas de Deus.' },
    ],
    3: [
      { v: 1, en: 'Then what advantage does the Jew have? Or what is the profit of circumcision?', pt: 'Que vantagem, pois, tem o judeu? ou qual a utilidade da circuncisão?' },
      { v: 2, en: 'Much in every way! Because first of all, they were entrusted with the revelations of God.', pt: 'Muita, em todo sentido; primeiramente, porque lhe foram confiados os oráculos de Deus.' },
      { v: 3, en: 'For what if some were without faith? Will their lack of faith nullify the faithfulness of God?', pt: 'Pois quê? Se alguns foram infiéis, porventura a sua infidelidade anulará a fidelidade de Deus?' },
      { v: 4, en: 'May it never be! Yes, let God be found true, but every man a liar. As it is written, “That you might be justified in your words, and might prevail when you come into judgment.”', pt: 'De modo nenhum; antes seja Deus verdadeiro, e todo homem mentiroso; como está escrito: Para que sejas justificado em tuas palavras, e venças quando fores julgado.' },
      { v: 5, en: 'But if our unrighteousness commends the righteousness of God, what will we say? Is God unrighteous who inflicts wrath? I speak like men do.', pt: 'E, se a nossa injustiça prova a justiça de Deus, que diremos? Acaso Deus, que castiga com ira, é injusto? (Falo como homem.)' },
      { v: 6, en: 'May it never be! For then how will God judge the world?', pt: 'De modo nenhum; do contrário, como julgará Deus o mundo?' },
      { v: 7, en: 'For if the truth of God through my lie abounded to his glory, why am I also still judged as a sinner?', pt: 'Mas, se pela minha mentira abundou mais a verdade de Deus para sua glória, por que sou eu ainda julgado como pecador?' },
      { v: 8, en: 'Why not (as we are slanderously reported, and as some affirm that we say), “Let us do evil, that good may come?” Those who say so are justly condemned.', pt: 'E por que não dizemos: Façamos o mal para que venha o bem? - como alguns caluniosamente afirmam que dizemos; a condenação dos quais é justa.' },
      { v: 9, en: 'What then? Are we better than they? No, in no way. For we previously warned both Jews and Greeks, that they are all under sin.', pt: 'Pois quê? Somos melhores do que eles? De maneira nenhuma, pois já demonstramos que, tanto judeus como gregos, todos estão debaixo do pecado;' },
      { v: 10, en: 'As it is written, “There is no one righteous; no, not one.', pt: 'como está escrito: Não há justo, nem sequer um.' },
      { v: 11, en: 'There is no one who understands. There is no one who seeks after God.', pt: 'Não há quem entenda; não há quem busque a Deus.' },
      { v: 12, en: 'They have all turned away. They have together become unprofitable. There is no one who does good, no, not so much as one.”', pt: 'Todos se extraviaram; juntamente se fizeram inúteis. Não há quem faça o bem, não há nem um só.' },
      { v: 13, en: '“Their throat is an open tomb. With their tongues they have used deceit.” “The poison of vipers is under their lips”;', pt: 'A sua garganta é um sepulcro aberto; com as suas línguas tratam enganosamente; peçonha de áspides está debaixo dos seus lábios;' },
      { v: 14, en: '“whose mouth is full of cursing and bitterness.”', pt: 'a sua boca está cheia de maldição e amargura.' },
      { v: 15, en: '“Their feet are swift to shed blood.', pt: 'Os seus pés são ligeiros para derramar sangue.' },
      { v: 16, en: 'Destruction and misery are in their ways.', pt: 'Nos seus caminhos há destruição e miséria;' },
      { v: 17, en: 'The way of peace, they haven’t known.”', pt: 'e não conheceram o caminho da paz.' },
      { v: 18, en: '“There is no fear of God before their eyes.”', pt: 'Não há temor de Deus diante dos seus olhos.' },
      { v: 19, en: 'Now we know that whatever things the law says, it speaks to those who are under the law, that every mouth may be closed, and all the world may be brought under the judgment of God.', pt: 'Ora, nós sabemos que tudo o que a lei diz, aos que estão debaixo da lei o diz, para que se cale toda boca e todo o mundo fique sujeito ao juízo de Deus;' },
      { v: 20, en: 'Because by the works of the law, no flesh will be justified in his sight. For through the law comes the knowledge of sin.', pt: 'porquanto pelas obras da lei nenhum homem será justificado diante dele; pois o que vem pela lei é o pleno conhecimento do pecado.' },
      { v: 21, en: 'But now apart from the law, a righteousness of God has been revealed, being testified by the law and the prophets;', pt: 'Mas agora, sem lei, tem-se manifestado a justiça de Deus, que é atestada pela lei e pelos profetas;' },
      { v: 22, en: 'even the righteousness of God through faith in Jesus Christ to all and on all those who believe. For there is no distinction,', pt: 'isto é, a justiça de Deus pela fé em Jesus Cristo para todos os que crêem; pois não há distinção.' },
      { v: 23, en: 'for all have sinned, and fall short of the glory of God;', pt: 'Porque todos pecaram e destituídos estão da glória de Deus;' },
      { v: 24, en: 'being justified freely by his grace through the redemption that is in Christ Jesus;', pt: 'sendo justificados gratuitamente pela sua graça, mediante a redenção que há em Cristo Jesus,' },
      { v: 25, en: 'whom God sent to be an atoning sacrifice, through faith in his blood, for a demonstration of his righteousness through the passing over of prior sins, in God’s forbearance;', pt: 'ao qual Deus propôs como propiciação, pela fé, no seu sangue, para demonstração da sua justiça por ter ele na sua paciência, deixado de lado os delitos outrora cometidos;' },
      { v: 26, en: 'to demonstrate his righteousness at this present time; that he might himself be just, and the justifier of him who has faith in Jesus.', pt: 'para demonstração da sua justiça neste tempo presente, para que ele seja justo e também justificador daquele que tem fé em Jesus.' },
      { v: 27, en: 'Where then is the boasting? It is excluded. By what kind of law? Of works? No, but by a law of faith.', pt: 'Onde está logo a jactância? Foi excluída. Por que lei? Das obras? Não; mas pela lei da fé.' },
      { v: 28, en: 'We maintain therefore that a man is justified by faith apart from the works of the law.', pt: 'concluímos pois que o homem é justificado pela fé sem as obras da lei.' },
      { v: 29, en: 'Or is God the God of Jews only? Isn’t he the God of Gentiles also? Yes, of Gentiles also,', pt: 'É porventura Deus somente dos judeus? Não é também dos gentios? Também dos gentios, certamente,' },
      { v: 30, en: 'since indeed there is one God who will justify the circumcised by faith, and the uncircumcised through faith.', pt: 'se é que Deus é um só, que pela fé há de justificar a circuncisão, e também por meio da fé a incircuncisão.' },
      { v: 31, en: 'Do we then nullify the law through faith? May it never be! No, we establish the law.', pt: 'Anulamos, pois, a lei pela fé? De modo nenhum; antes estabelecemos a lei.' },
    ],
    4: [
      { v: 1, en: 'What then will we say that Abraham, our forefather, has found according to the flesh?', pt: 'Que diremos, pois, ter alcançado Abraão, nosso pai segundo a carne?' },
      { v: 2, en: 'For if Abraham was justified by works, he has something to boast about, but not toward God.', pt: 'Porque, se Abraão foi justificado pelas obras, tem de que se gloriar, mas não diante de Deus.' },
      { v: 3, en: 'For what does the Scripture say? “Abraham believed God, and it was accounted to him for righteousness.”', pt: 'Pois, que diz a Escritura? Creu Abraão a Deus, e isso lhe foi imputado como justiça.' },
      { v: 4, en: 'Now to him who works, the reward is not counted as grace, but as something owed.', pt: 'Ora, ao que trabalha não se lhe conta a recompensa como dádiva, mas sim como dívida;' },
      { v: 5, en: 'But to him who doesn’t work, but believes in him who justifies the ungodly, his faith is accounted for righteousness.', pt: 'porém ao que não trabalha, mas crê naquele que justifica o ímpio, a sua fé lhe é contada como justiça;' },
      { v: 6, en: 'Even as David also pronounces blessing on the man to whom God counts righteousness apart from works,', pt: 'assim também Davi declara bem-aventurado o homem a quem Deus atribui a justiça sem as obras, dizendo:' },
      { v: 7, en: '“Blessed are they whose iniquities are forgiven, whose sins are covered.', pt: 'Bem-aventurados aqueles cujas iniqüidades são perdoadas, e cujos pecados são cobertos.' },
      { v: 8, en: 'Blessed is the man whom the Lord will by no means charge with sin.”', pt: 'Bem-aventurado o homem a quem o Senhor não imputará o pecado.' },
      { v: 9, en: 'Is this blessing then pronounced on the circumcised, or on the uncircumcised also? For we say that faith was accounted to Abraham for righteousness.', pt: 'Vem, pois, esta bem-aventurança sobre a circuncisão somente, ou também sobre a incircuncisão? Porque dizemos: A Abraão foi imputada a fé como justiça.' },
      { v: 10, en: 'How then was it counted? When he was in circumcision, or in uncircumcision? Not in circumcision, but in uncircumcision.', pt: 'Como, pois, lhe foi imputada? Estando na circuncisão, ou na incircuncisão? Não na circuncisão, mas sim na incircuncisão.' },
      { v: 11, en: 'He received the sign of circumcision, a seal of the righteousness of the faith which he had while he was in uncircumcision, that he might be the father of all those who believe, though they might be in uncircumcision, that righteousness might also be accounted to them.', pt: 'E recebeu o sinal da circuncisão, selo da justiça da fé que teve quando ainda não era circuncidado, para que fosse pai de todos os que crêem, estando eles na incircuncisão, a fim de que a justiça lhes seja imputada,' },
      { v: 12, en: 'He is the father of circumcision to those who not only are of the circumcision, but who also walk in the steps of that faith of our father Abraham, which he had in uncircumcision.', pt: 'bem como fosse pai dos circuncisos, dos que não somente são da circuncisão, mas também andam nas pisadas daquela fé que teve nosso pai Abraão, antes de ser circuncidado.' },
      { v: 13, en: 'For the promise to Abraham and to his offspring that he should be heir of the world wasn’t through the law, but through the righteousness of faith.', pt: 'Porque não foi pela lei que veio a Abraão, ou à sua descendência, a promessa de que havia de ser herdeiro do mundo, mas pela justiça da fé.' },
      { v: 14, en: 'For if those who are of the law are heirs, faith is made void, and the promise is made of no effect.', pt: 'Pois, se os que são da lei são herdeiros, logo a fé é vã e a promessa é anulada.' },
      { v: 15, en: 'For the law produces wrath, for where there is no law, neither is there disobedience.', pt: 'Porque a lei opera a ira; mas onde não há lei também não há transgressão.' },
      { v: 16, en: 'For this cause it is of faith, that it may be according to grace, to the end that the promise may be sure to all the offspring, not to that only which is of the law, but to that also which is of the faith of Abraham, who is the father of us all.', pt: 'Porquanto procede da fé o ser herdeiro, para que seja segundo a graça, a fim de que a promessa seja firme a toda a descendência, não somente à que é da lei, mas também à que é da fé que teve Abraão, o qual é pai de todos nós.' },
      { v: 17, en: 'As it is written, “I have made you a father of many nations.” This is in the presence of him whom he believed: God, who gives life to the dead, and calls the things that are not, as though they were.', pt: '(como está escrito: Por pai de muitas nações te constituí) perante aquele no qual creu, a saber, Deus, que vivifica os mortos, e chama as coisas que não são, como se já fossem.' },
      { v: 18, en: 'Besides hope, Abraham in hope believed, to the end that he might become a father of many nations, according to that which had been spoken, “So will your offspring be.”', pt: 'O qual, em esperança, creu contra a esperança, para que se tornasse pai de muitas nações, conforme o que lhe fora dito: Assim será a tua descendência;' },
      { v: 19, en: 'Without being weakened in faith, he didn’t consider his own body, already having been worn out, (he being about a hundred years old), and the deadness of Sarah’s womb.', pt: 'e sem se enfraquecer na fé, considerou o seu próprio corpo já amortecido (pois tinha quase cem anos), e o amortecimento do ventre de Sara;' },
      { v: 20, en: 'Yet, looking to the promise of God, he didn’t waver through unbelief, but grew strong through faith, giving glory to God,', pt: 'contudo, à vista da promessa de Deus, não vacilou por incredulidade, antes foi fortalecido na fé, dando glória a Deus,' },
      { v: 21, en: 'and being fully assured that what he had promised, he was also able to perform.', pt: 'e estando certíssimo de que o que Deus tinha prometido, também era poderoso para o fazer.' },
      { v: 22, en: 'Therefore it also was “credited to him for righteousness.”', pt: 'Pelo que também isso lhe foi imputado como justiça.' },
      { v: 23, en: 'Now it was not written that it was accounted to him for his sake alone,', pt: 'Ora, não é só por causa dele que está escrito que lhe foi imputado;' },
      { v: 24, en: 'but for our sake also, to whom it will be accounted, who believe in him who raised Jesus, our Lord, from the dead,', pt: 'mas também por causa de nós a quem há de ser imputado, a nós os que cremos naquele que dos mortos ressuscitou a Jesus nosso Senhor;' },
      { v: 25, en: 'who was delivered up for our trespasses, and was raised for our justification.', pt: 'o qual foi entregue por causa das nossas transgressões, e ressuscitado para a nossa justificação.' },
    ],
    5: [
      { v: 1, en: 'Being therefore justified by faith, we have peace with God through our Lord Jesus Christ;', pt: 'Justificados, pois, pela fé, tenhamos paz com Deus, por nosso Senhor Jesus Cristo,' },
      { v: 2, en: 'through whom we also have our access by faith into this grace in which we stand. We rejoice in hope of the glory of God.', pt: 'por quem obtivemos também nosso acesso pela fé a esta graça, na qual estamos firmes, e gloriemo-nos na esperança da glória de Deus.' },
      { v: 3, en: 'Not only this, but we also rejoice in our sufferings, knowing that suffering produces perseverance;', pt: 'E não somente isso, mas também gloriemo-nos nas tribulações; sabendo que a tribulação produz a perseverança,' },
      { v: 4, en: 'and perseverance, proven character; and proven character, hope:', pt: 'e a perseverança a experiência, e a experiência a esperança;' },
      { v: 5, en: 'and hope doesn’t disappoint us, because God’s love has been poured out into our hearts through the Holy Spirit who was given to us.', pt: 'e a esperança não desaponta, porquanto o amor de Deus está derramado em nossos corações pelo Espírito Santo que nos foi dado.' },
      { v: 6, en: 'For while we were yet weak, at the right time Christ died for the ungodly.', pt: 'Pois, quando ainda éramos fracos, Cristo morreu a seu tempo pelos ímpios.' },
      { v: 7, en: 'For one will hardly die for a righteous man. Yet perhaps for a righteous person someone would even dare to die.', pt: 'Porque dificilmente haverá quem morra por um justo; pois poderá ser que pelo homem bondoso alguém ouse morrer.' },
      { v: 8, en: 'But God commends his own love toward us, in that while we were yet sinners, Christ died for us.', pt: 'Mas Deus dá prova do seu amor para conosco, em que, quando éramos ainda pecadores, Cristo morreu por nós.' },
      { v: 9, en: 'Much more then, being now justified by his blood, we will be saved from God’s wrath through him.', pt: 'Logo muito mais, sendo agora justificados pelo seu sangue, seremos por ele salvos da ira.' },
      { v: 10, en: 'For if, while we were enemies, we were reconciled to God through the death of his Son, much more, being reconciled, we will be saved by his life.', pt: 'Porque se nós, quando éramos inimigos, fomos reconciliados com Deus pela morte de seu Filho, muito mais, estando já reconciliados, seremos salvos pela sua vida.' },
      { v: 11, en: 'Not only so, but we also rejoice in God through our Lord Jesus Christ, through whom we have now received the reconciliation.', pt: 'E não somente isso, mas também nos gloriamos em Deus por nosso Senhor Jesus Cristo, pelo qual agora temos recebido a reconciliação.' },
      { v: 12, en: 'Therefore as sin entered into the world through one man, and death through sin; and so death passed to all men, because all sinned.', pt: 'Portanto, assim como por um só homem entrou o pecado no mundo, e pelo pecado a morte, assim também a morte passou a todos os homens, porquanto todos pecaram.' },
      { v: 13, en: 'For until the law, sin was in the world; but sin is not charged when there is no law.', pt: 'Porque antes da lei já estava o pecado no mundo, mas onde não há lei o pecado não é levado em conta.' },
      { v: 14, en: 'Nevertheless death reigned from Adam until Moses, even over those whose sins weren’t like Adam’s disobedience, who is a foreshadowing of him who was to come.', pt: 'No entanto a morte reinou desde Adão até Moisés, mesmo sobre aqueles que não pecaram à semelhança da transgressão de Adão o qual é figura daquele que havia de vir.' },
      { v: 15, en: 'But the free gift isn’t like the trespass. For if by the trespass of the one the many died, much more did the grace of God, and the gift by the grace of the one man, Jesus Christ, abound to the many.', pt: 'Mas não é assim o dom gratuito como a ofensa; porque, se pela ofensa de um morreram muitos, muito mais a graça de Deus, e o dom pela graça de um só homem, Jesus Cristo, abund muitos.' },
      { v: 16, en: 'The gift is not as through one who sinned: for the judgment came by one to condemnation, but the free gift came of many trespasses to justification.', pt: 'Também não é assim o dom como a ofensa, que veio por um só que pecou; porque o juízo veio, na verdade, de uma só ofensa para condenação, mas o dom gratuito veio de muitas ofensas para justificação.' },
      { v: 17, en: 'For if by the trespass of the one, death reigned through the one; so much more will those who receive the abundance of grace and of the gift of righteousness reign in life through the one, Jesus Christ.', pt: 'Porque, se pela ofensa de um só, a morte veio a reinar por esse, muito mais os que recebem a abundância da graça, e do dom da justiça, reinarão em vida por um só, Jesus Cristo.' },
      { v: 18, en: 'So then as through one trespass, all men were condemned; even so through one act of righteousness, all men were justified to life.', pt: 'Portanto, assim como por uma só ofensa veio o juízo sobre todos os homens para condenação, assim também por um só ato de justiça veio a graça sobre todos os homens para justificação e vida.' },
      { v: 19, en: 'For as through the one man’s disobedience many were made sinners, even so through the obedience of the one, many will be made righteous.', pt: 'Porque, assim como pela desobediência de um só homem muitos foram constituídos pecadores, assim também pela obediência de um muitos serão constituídos justos.' },
      { v: 20, en: 'The law came in besides, that the trespass might abound; but where sin abounded, grace abounded more exceedingly;', pt: 'Sobreveio, porém, a lei para que a ofensa abundasse; mas, onde o pecado abundou, superabundou a graça;' },
      { v: 21, en: 'that as sin reigned in death, even so grace might reign through righteousness to eternal life through Jesus Christ our Lord.', pt: 'para que, assim como o pecado veio a reinar na morte, assim também viesse a reinar a graça pela justiça para a vida eterna, por Jesus Cristo nosso Senhor.' },
    ],
    6: [
      { v: 1, en: 'What shall we say then? Shall we continue in sin, that grace may abound?', pt: 'Que diremos, pois? Permaneceremos no pecado, para que abunde a graça?' },
      { v: 2, en: 'May it never be! We who died to sin, how could we live in it any longer?', pt: 'De modo nenhum. Nós, que já morremos para o pecado, como viveremos ainda nele?' },
      { v: 3, en: 'Or don’t you know that all we who were baptized into Christ Jesus were baptized into his death?', pt: 'Ou, porventura, ignorais que todos quantos fomos batizados em Cristo Jesus fomos batizados na sua morte?' },
      { v: 4, en: 'We were buried therefore with him through baptism into death, that just as Christ was raised from the dead through the glory of the Father, so we also might walk in newness of life.', pt: 'Fomos, pois, sepultados com ele pelo batismo na morte, para que, como Cristo foi ressuscitado dentre os mortos pela glória do Pai, assim andemos nós também em novidade de vida.' },
      { v: 5, en: 'For if we have become united with him in the likeness of his death, we will also be part of his resurrection;', pt: 'Porque, se temos sido unidos a ele na semelhança da sua morte, certamente também o seremos na semelhança da sua ressurreição;' },
      { v: 6, en: 'knowing this, that our old man was crucified with him, that the body of sin might be done away with, so that we would no longer be in bondage to sin.', pt: 'sabendo isto, que o nosso homem velho foi crucificado com ele, para que o corpo do pecado fosse desfeito, a fim de não servirmos mais ao pecado.' },
      { v: 7, en: 'For he who has died has been freed from sin.', pt: 'Pois quem está morto está justificado do pecado.' },
      { v: 8, en: 'But if we died with Christ, we believe that we will also live with him;', pt: 'Ora, se já morremos com Cristo, cremos que também com ele viveremos,' },
      { v: 9, en: 'knowing that Christ, being raised from the dead, dies no more. Death no more has dominion over him!', pt: 'sabendo que, tendo Cristo ressurgido dentre os mortos, já não morre mais; a morte não mais tem domínio sobre ele.' },
      { v: 10, en: 'For the death that he died, he died to sin one time; but the life that he lives, he lives to God.', pt: 'Pois quanto a ter morrido, de uma vez por todas morreu para o pecado, mas quanto a viver, vive para Deus.' },
      { v: 11, en: 'Thus consider yourselves also to be dead to sin, but alive to God in Christ Jesus our Lord.', pt: 'Assim também vós considerai-vos como mortos para o pecado, mas vivos para Deus, em Cristo Jesus.' },
      { v: 12, en: 'Therefore don’t let sin reign in your mortal body, that you should obey it in its lusts.', pt: 'Não reine, portanto, o pecado em vosso corpo mortal, para obedecerdes às suas concupiscências;' },
      { v: 13, en: 'Also, do not present your members to sin as instruments of unrighteousness, but present yourselves to God, as alive from the dead, and your members as instruments of righteousness to God.', pt: 'nem tampouco apresenteis os vossos membros ao pecado como instrumentos de iniqüidade; mas apresentai-vos a Deus, como redivivos dentre os mortos, e os vossos membros a Deus, como instrumentos de justiça.' },
      { v: 14, en: 'For sin will not have dominion over you. For you are not under law, but under grace.', pt: 'Pois o pecado não terá domínio sobre vós, porquanto não estais debaixo da lei, mas debaixo da graça.' },
      { v: 15, en: 'What then? Shall we sin, because we are not under law, but under grace? May it never be!', pt: 'Pois quê? Havemos de pecar porque não estamos debaixo da lei, mas debaixo da graça? De modo nenhum.' },
      { v: 16, en: 'Don’t you know that when you present yourselves as servants and obey someone, you are the servants of whomever you obey; whether of sin to death, or of obedience to righteousness?', pt: 'Não sabeis que daquele a quem vos apresentais como servos para lhe obedecer, sois servos desse mesmo a quem obedeceis, seja do pecado para a morte, ou da obediência para a justiça?' },
      { v: 17, en: 'But thanks be to God, that, whereas you were bondservants of sin, you became obedient from the heart to that form of teaching to which you were delivered.', pt: 'Mas graças a Deus que, embora tendo sido servos do pecado, obedecestes de coração à forma de doutrina a que fostes entregues;' },
      { v: 18, en: 'Being made free from sin, you became bondservants of righteousness.', pt: 'e libertos do pecado, fostes feitos servos da justiça.' },
      { v: 19, en: 'I speak in human terms because of the weakness of your flesh, for as you presented your members as servants to uncleanness and to wickedness upon wickedness, even so now present your members as servants to righteousness for sanctification.', pt: 'Falo como homem, por causa da fraqueza da vossa carne. Pois assim como apresentastes os vossos membros como servos da impureza e da iniqüidade para iniqüidade, assim apresentai agora os vossos membros como servos da justiça para santificação.' },
      { v: 20, en: 'For when you were servants of sin, you were free in regard to righteousness.', pt: 'Porque, quando éreis servos do pecado, estáveis livres em relação à justiça.' },
      { v: 21, en: 'What fruit then did you have at that time in the things of which you are now ashamed? For the end of those things is death.', pt: 'E que fruto tínheis então das coisas de que agora vos envergonhais? pois o fim delas é a morte.' },
      { v: 22, en: 'But now, being made free from sin, and having become servants of God, you have your fruit of sanctification, and the result of eternal life.', pt: 'Mas agora, libertos do pecado, e feitos servos de Deus, tendes o vosso fruto para santificação, e por fim a vida eterna.' },
      { v: 23, en: 'For the wages of sin is death, but the free gift of God is eternal life in Christ Jesus our Lord.', pt: 'Porque o salário do pecado é a morte, mas o dom gratuito de Deus é a vida eterna em Cristo Jesus nosso Senhor.' },
    ],
    7: [
      { v: 1, en: 'Or don’t you know, brothers (for I speak to men who know the law), that the law has dominion over a man for as long as he lives?', pt: 'Ou ignorais, irmãos (pois falo aos que conhecem a lei), que a lei tem domínio sobre o homem por todo o tempo que ele vive?' },
      { v: 2, en: 'For the woman that has a husband is bound by law to the husband while he lives, but if the husband dies, she is discharged from the law of the husband.', pt: 'Porque a mulher casada está ligada pela lei a seu marido enquanto ele viver; mas, se ele morrer, ela está livre da lei do marido.' },
      { v: 3, en: 'So then if, while the husband lives, she is joined to another man, she would be called an adulteress. But if the husband dies, she is free from the law, so that she is no adulteress, though she is joined to another man.', pt: 'De sorte que, enquanto viver o marido, será chamado adúltera, se for de outro homem; mas, se ele morrer, ela está livre da lei, e assim não será adúltera se for de outro marido.' },
      { v: 4, en: 'Therefore, my brothers, you also were made dead to the law through the body of Christ, that you would be joined to another, to him who was raised from the dead, that we might produce fruit to God.', pt: 'Assim também vós, meus irmãos, fostes mortos quanto à lei mediante o corpo de Cristo, para pertencerdes a outro, àquele que ressurgiu dentre os mortos a fim de que demos fruto para Deus.' },
      { v: 5, en: 'For when we were in the flesh, the sinful passions which were through the law, worked in our members to bring out fruit to death.', pt: 'Pois, quando estávamos na carne, as paixões dos pecados, suscitadas pela lei, operavam em nossos membros para darem fruto para a morte.' },
      { v: 6, en: 'But now we have been discharged from the law, having died to that in which we were held; so that we serve in newness of the spirit, and not in oldness of the letter.', pt: 'Mas agora fomos libertos da lei, havendo morrido para aquilo em que estávamos retidos, para servirmos em novidade de espírito, e não na velhice da letra.' },
      { v: 7, en: 'What shall we say then? Is the law sin? May it never be! However, I wouldn’t have known sin, except through the law. For I wouldn’t have known coveting, unless the law had said, “You shall not covet.”', pt: 'Que diremos pois? É a lei pecado? De modo nenhum. Contudo, eu não conheci o pecado senão pela lei; porque eu não conheceria a concupiscência, se a lei não dissesse: Não cobiçarás.' },
      { v: 8, en: 'But sin, finding occasion through the commandment, produced in me all kinds of coveting. For apart from the law, sin is dead.', pt: 'Mas o pecado, tomando ocasião, pelo mandamento operou em mim toda espécie de concupiscência; porquanto onde não há lei está morto o pecado.' },
      { v: 9, en: 'I was alive apart from the law once, but when the commandment came, sin revived, and I died.', pt: 'E outrora eu vivia sem a lei; mas assim que veio o mandamento, reviveu o pecado, e eu morri;' },
      { v: 10, en: 'The commandment, which was for life, this I found to be for death;', pt: 'e o mandamento que era para vida, esse achei que me era para morte.' },
      { v: 11, en: 'for sin, finding occasion through the commandment, deceived me, and through it killed me.', pt: 'Porque o pecado, tomando ocasião, pelo mandamento me enganou, e por ele me matou.' },
      { v: 12, en: 'Therefore the law indeed is holy, and the commandment holy, and righteous, and good.', pt: 'De modo que a lei é santa, e o mandamento santo, justo e bom.' },
      { v: 13, en: 'Did then that which is good become death to me? May it never be! But sin, that it might be shown to be sin, was producing death in me through that which is good; that through the commandment sin might become exceedingly sinful.', pt: 'Logo o bom tornou-se morte para mim? De modo nenhum; mas o pecado, para que se mostrasse pecado, operou em mim a morte por meio do bem; a fim de que pelo mandamento o pecado se manifestasse excessivamente maligno.' },
      { v: 14, en: 'For we know that the law is spiritual, but I am fleshly, sold under sin.', pt: 'Porque bem sabemos que a lei é espiritual; mas eu sou carnal, vendido sob o pecado.' },
      { v: 15, en: 'For I don’t know what I am doing. For I don’t practice what I desire to do; but what I hate, that I do.', pt: 'Pois o que faço, não o entendo; porque o que quero, isso não pratico; mas o que aborreço, isso faço.' },
      { v: 16, en: 'But if what I don’t desire, that I do, I consent to the law that it is good.', pt: 'E, se faço o que não quero, consinto com a lei, que é boa.' },
      { v: 17, en: 'So now it is no more I that do it, but sin which dwells in me.', pt: 'Agora, porém, não sou mais eu que faço isto, mas o pecado que habita em mim.' },
      { v: 18, en: 'For I know that in me, that is, in my flesh, dwells no good thing. For desire is present with me, but I don’t find it doing that which is good.', pt: 'Porque eu sei que em mim, isto é, na minha carne, não habita bem algum; com efeito o querer o bem está em mim, mas o efetuá-lo não está.' },
      { v: 19, en: 'For the good which I desire, I don’t do; but the evil which I don’t desire, that I practice.', pt: 'Pois não faço o bem que quero, mas o mal que não quero, esse pratico.' },
      { v: 20, en: 'But if what I don’t desire, that I do, it is no more I that do it, but sin which dwells in me.', pt: 'Ora, se eu faço o que não quero, já o não faço eu, mas o pecado que habita em mim.' },
      { v: 21, en: 'I find then the law, that, to me, while I desire to do good, evil is present.', pt: 'Acho então esta lei em mim, que, mesmo querendo eu fazer o bem, o mal está comigo.' },
      { v: 22, en: 'For I delight in God’s law after the inward man,', pt: 'Porque, segundo o homem interior, tenho prazer na lei de Deus;' },
      { v: 23, en: 'but I see a different law in my members, warring against the law of my mind, and bringing me into captivity under the law of sin which is in my members.', pt: 'mas vejo nos meus membros outra lei guerreando contra a lei do meu entendimento, e me levando cativo à lei do pecado, que está nos meus membros.' },
      { v: 24, en: 'What a wretched man I am! Who will deliver me out of the body of this death?', pt: 'Miserável homem que eu sou! quem me livrará do corpo desta morte?' },
      { v: 25, en: 'I thank God through Jesus Christ, our Lord! So then with the mind, I myself serve God’s law, but with the flesh, the sin’s law.', pt: 'Graças a Deus, por Jesus Cristo nosso Senhor! De modo que eu mesmo com o entendimento sirvo à lei de Deus, mas com a carne à lei do pecado.' },
    ],
    8: [
      { v: 1, en: 'There is therefore now no condemnation to those who are in Christ Jesus, who don’t walk according to the flesh, but according to the Spirit.', pt: 'Portanto, agora nenhuma condenação há para os que estão em Cristo Jesus.' },
      { v: 2, en: 'For the law of the Spirit of life in Christ Jesus made me free from the law of sin and of death.', pt: 'Porque a lei do Espírito da vida, em Cristo Jesus, te livrou da lei do pecado e da morte.' },
      { v: 3, en: 'For what the law couldn’t do, in that it was weak through the flesh, God did, sending his own Son in the likeness of sinful flesh and for sin, he condemned sin in the flesh;', pt: 'Porquanto o que era impossível à lei, visto que se achava fraca pela carne, Deus enviando o seu próprio Filho em semelhança da carne do pecado, e por causa do pecado, na carne condenou o pecado.' },
      { v: 4, en: 'that the ordinance of the law might be fulfilled in us, who walk not after the flesh, but after the Spirit.', pt: 'para que a justa exigência da lei se cumprisse em nós, que não andamos segundo a carne, mas segundo o Espírito.' },
      { v: 5, en: 'For those who live according to the flesh set their minds on the things of the flesh, but those who live according to the Spirit, the things of the Spirit.', pt: 'Pois os que são segundo a carne inclinam-se para as coisas da carne; mas os que são segundo o Espírito para as coisas do Espírito.' },
      { v: 6, en: 'For the mind of the flesh is death, but the mind of the Spirit is life and peace;', pt: 'Porque a inclinação da carne é morte; mas a inclinação do Espírito é vida e paz.' },
      { v: 7, en: 'because the mind of the flesh is hostile towards God; for it is not subject to God’s law, neither indeed can it be.', pt: 'Porquanto a inclinação da carne é inimizade contra Deus, pois não é sujeita à lei de Deus, nem em verdade o pode ser;' },
      { v: 8, en: 'Those who are in the flesh can’t please God.', pt: 'e os que estão na carne não podem agradar a Deus.' },
      { v: 9, en: 'But you are not in the flesh but in the Spirit, if it is so that the Spirit of God dwells in you. But if any man doesn’t have the Spirit of Christ, he is not his.', pt: 'Vós, porém, não estais na carne, mas no Espírito, se é que o Espírito de Deus habita em vós. Mas, se alguém não tem o Espírito de Cristo, esse tal não é dele.' },
      { v: 10, en: 'If Christ is in you, the body is dead because of sin, but the spirit is alive because of righteousness.', pt: 'Ora, se Cristo está em vós, o corpo, na verdade, está morto por causa do pecado, mas o espírito vive por causa da justiça.' },
      { v: 11, en: 'But if the Spirit of him who raised up Jesus from the dead dwells in you, he who raised up Christ Jesus from the dead will also give life to your mortal bodies through his Spirit who dwells in you.', pt: 'E, se o Espírito daquele que dos mortos ressuscitou a Jesus habita em vós, aquele que dos mortos ressuscitou a Cristo Jesus há de vivificar também os vossos corpos mortais, pelo seu Espírito que em vós habita.' },
      { v: 12, en: 'So then, brothers, we are debtors, not to the flesh, to live after the flesh.', pt: 'Portanto, irmãos, somos devedores, não à carne para vivermos segundo a carne;' },
      { v: 13, en: 'For if you live after the flesh, you must die; but if by the Spirit you put to death the deeds of the body, you will live.', pt: 'porque se viverdes segundo a carne, haveis de morrer; mas, se pelo Espírito mortificardes as obras do corpo, vivereis.' },
      { v: 14, en: 'For as many as are led by the Spirit of God, these are children of God.', pt: 'Pois todos os que são guiados pelo Espírito de Deus, esses são filhos de Deus.' },
      { v: 15, en: 'For you didn’t receive the spirit of bondage again to fear, but you received the Spirit of adoption, by whom we cry, “Abba! Father!”', pt: 'Porque não recebestes o espírito de escravidão, para outra vez estardes com temor, mas recebestes o espírito de adoção, pelo qual clamamos: Aba, Pai!' },
      { v: 16, en: 'The Spirit himself testifies with our spirit that we are children of God;', pt: 'O Espírito mesmo testifica com o nosso espírito que somos filhos de Deus;' },
      { v: 17, en: 'and if children, then heirs; heirs of God, and joint heirs with Christ; if indeed we suffer with him, that we may also be glorified with him.', pt: 'e, se filhos, também herdeiros, herdeiros de Deus e co-herdeiros de Cristo; se é certo que com ele padecemos, para que também com ele sejamos glorificados.' },
      { v: 18, en: 'For I consider that the sufferings of this present time are not worthy to be compared with the glory which will be revealed toward us.', pt: 'Pois tenho para mim que as aflições deste tempo presente não se podem comparar com a glória que em nós há de ser revelada.' },
      { v: 19, en: 'For the creation waits with eager expectation for the children of God to be revealed.', pt: 'Porque a criação aguarda com ardente expectativa a revelação dos filhos de Deus.' },
      { v: 20, en: 'For the creation was subjected to vanity, not of its own will, but because of him who subjected it, in hope', pt: 'Porquanto a criação ficou sujeita à vaidade, não por sua vontade, mas por causa daquele que a sujeitou,' },
      { v: 21, en: 'that the creation itself also will be delivered from the bondage of decay into the liberty of the glory of the children of God.', pt: 'na esperança de que também a própria criação há de ser liberta do cativeiro da corrupção, para a liberdade da glória dos filhos de Deus.' },
      { v: 22, en: 'For we know that the whole creation groans and travails in pain together until now.', pt: 'Porque sabemos que toda a criação, conjuntamente, geme e está com dores de parto até agora;' },
      { v: 23, en: 'Not only so, but ourselves also, who have the first fruits of the Spirit, even we ourselves groan within ourselves, waiting for adoption, the redemption of our body.', pt: 'e não só ela, mas até nós, que temos as primícias do Espírito, também gememos em nós mesmos, aguardando a nossa adoração, a saber, a redenção do nosso corpo.' },
      { v: 24, en: 'For we were saved in hope, but hope that is seen is not hope. For who hopes for that which he sees?', pt: 'Porque na esperança fomos salvos. Ora, a esperança que se vê não é esperança; pois o que alguém vê, como o espera?' },
      { v: 25, en: 'But if we hope for that which we don’t see, we wait for it with patience.', pt: 'Mas, se esperamos o que não vemos, com paciência o aguardamos.' },
      { v: 26, en: 'In the same way, the Spirit also helps our weaknesses, for we don’t know how to pray as we ought. But the Spirit himself makes intercession for us with groanings which can’t be uttered.', pt: 'Do mesmo modo também o Espírito nos ajuda na fraqueza; porque não sabemos o que havemos de pedir como convém, mas o Espírito mesmo intercede por nós com gemidos inexprimíveis.' },
      { v: 27, en: 'He who searches the hearts knows what is on the Spirit’s mind, because he makes intercession for the saints according to God.', pt: 'E aquele que esquadrinha os corações sabe qual é a intenção do Espírito: que ele, segundo a vontade de Deus, intercede pelos santos.' },
      { v: 28, en: 'We know that all things work together for good for those who love God, to those who are called according to his purpose.', pt: 'E sabemos que todas as coisas concorrem para o bem daqueles que amam a Deus, daqueles que são chamados segundo o seu propósito.' },
      { v: 29, en: 'For whom he foreknew, he also predestined to be conformed to the image of his Son, that he might be the firstborn among many brothers.', pt: 'Porque os que dantes conheceu, também os predestinou para serem conformes à imagem de seu Filho, a fim de que ele seja o primogênito entre muitos irmãos;' },
      { v: 30, en: 'Whom he predestined, those he also called. Whom he called, those he also justified. Whom he justified, those he also glorified.', pt: 'e aos que predestinou, a estes também chamou; e aos que chamou, a estes também justificou; e aos que justificou, a estes também glorificou.' },
      { v: 31, en: 'What then shall we say about these things? If God is for us, who can be against us?', pt: 'Que diremos, pois, a estas coisas? Se Deus é por nós, quem será contra nós?' },
      { v: 32, en: 'He who didn’t spare his own Son, but delivered him up for us all, how would he not also with him freely give us all things?', pt: 'Aquele que nem mesmo a seu próprio Filho poupou, antes o entregou por todos nós, como não nos dará também com ele todas as coisas?' },
      { v: 33, en: 'Who could bring a charge against God’s chosen ones? It is God who justifies.', pt: 'Quem intentará acusação contra os escolhidos de Deus? É Deus quem os justifica;' },
      { v: 34, en: 'Who is he who condemns? It is Christ who died, yes rather, who was raised from the dead, who is at the right hand of God, who also makes intercession for us.', pt: 'Quem os condenará? Cristo Jesus é quem morreu, ou antes quem ressurgiu dentre os mortos, o qual está à direita de Deus, e também intercede por nós;' },
      { v: 35, en: 'Who shall separate us from the love of Christ? Could oppression, or anguish, or persecution, or famine, or nakedness, or peril, or sword?', pt: 'quem nos separará do amor de Cristo? a tribulação, ou a angústia, ou a perseguição, ou a fome, ou a nudez, ou o perigo, ou a espada?' },
      { v: 36, en: 'Even as it is written, “For your sake we are killed all day long. We were accounted as sheep for the slaughter.”', pt: 'Como está escrito: Por amor de ti somos entregues à morte o dia todo; fomos considerados como ovelhas para o matadouro.' },
      { v: 37, en: 'No, in all these things, we are more than conquerors through him who loved us.', pt: 'Mas em todas estas coisas somos mais que vencedores, por aquele que nos amou.' },
      { v: 38, en: 'For I am persuaded that neither death, nor life, nor angels, nor principalities, nor things present, nor things to come, nor powers,', pt: 'Porque estou certo de que, nem a morte, nem a vida, nem anjos, nem principados, nem coisas presentes, nem futuras, nem potestades,' },
      { v: 39, en: 'nor height, nor depth, nor any other created thing, will be able to separate us from God’s love, which is in Christ Jesus our Lord.', pt: 'nem a altura, nem a profundidade, nem qualquer outra criatura nos poderá separar do amor de Deus, que está em Cristo Jesus nosso Senhor.' },
    ],
    9: [
      { v: 1, en: 'I tell the truth in Christ. I am not lying, my conscience testifying with me in the Holy Spirit,', pt: 'Digo a verdade em Cristo, não minto, dando testemunho comigo a minha consciência no Espírito Santo,' },
      { v: 2, en: 'that I have great sorrow and unceasing pain in my heart.', pt: 'que tenho grande tristeza e incessante dor no meu coração.' },
      { v: 3, en: 'For I could wish that I myself were accursed from Christ for my brothers’ sake, my relatives according to the flesh,', pt: 'Porque eu mesmo desejaria ser separado de Cristo, por amor de meus irmãos, que são meus parentes segundo a carne;' },
      { v: 4, en: 'who are Israelites; whose is the adoption, the glory, the covenants, the giving of the law, the service, and the promises;', pt: 'os quais são israelitas, de quem é a adoção, e a glória, e os pactos, e a promulgação da lei, e o culto, e as promessas;' },
      { v: 5, en: 'of whom are the fathers, and from whom is Christ as concerning the flesh, who is over all, God, blessed forever. Amen.', pt: 'de quem são os patriarcas; e de quem descende o Cristo segundo a carne, o qual é sobre todas as coisas, Deus bendito eternamente. Amém.' },
      { v: 6, en: 'But it is not as though the word of God has come to nothing. For they are not all Israel, that are of Israel.', pt: 'Não que a palavra de Deus haja falhado. Porque nem todos os que são de Israel são israelitas;' },
      { v: 7, en: 'Neither, because they are Abraham’s offspring, are they all children. But, “your offspring will be accounted as from Isaac.”', pt: 'nem por serem descendência de Abraão são todos filhos; mas: Em Isaque será chamada a tua descendência.' },
      { v: 8, en: 'That is, it is not the children of the flesh who are children of God, but the children of the promise are counted as heirs.', pt: 'Isto é, não são os filhos da carne que são filhos de Deus; mas os filhos da promessa são contados como descendência.' },
      { v: 9, en: 'For this is a word of promise, “At the appointed time I will come, and Sarah will have a son.”', pt: 'Porque a palavra da promessa é esta: Por este tempo virei, e Sara terá um filho.' },
      { v: 10, en: 'Not only so, but Rebekah also conceived by one, by our father Isaac.', pt: 'E não somente isso, mas também a Rebeca, que havia concebido de um, de Isaque, nosso pai' },
      { v: 11, en: 'For being not yet born, neither having done anything good or bad, that the purpose of God according to election might stand, not of works, but of him who calls,', pt: '(pois não tendo os gêmeos ainda nascido, nem tendo praticado bem ou mal, para que o propósito de Deus segundo a eleição permanecesse firme, não por causa das obras, mas por aquele que chama),' },
      { v: 12, en: 'it was said to her, “The elder will serve the younger.”', pt: 'foi-lhe dito: O maior servirá o menor.' },
      { v: 13, en: 'Even as it is written, “Jacob I loved, but Esau I hated.”', pt: 'Como está escrito: Amei a Jacó, e aborreci a Esaú.' },
      { v: 14, en: 'What shall we say then? Is there unrighteousness with God? May it never be!', pt: 'Que diremos, pois? Há injustiça da parte de Deus? De modo nenhum.' },
      { v: 15, en: 'For he said to Moses, “I will have mercy on whom I have mercy, and I will have compassion on whom I have compassion.”', pt: 'Porque diz a Moisés: Terei misericórdia de quem me aprouver ter misericordia, e terei compaixão de quem me aprouver ter compaixão.' },
      { v: 16, en: 'So then it is not of him who wills, nor of him who runs, but of God who has mercy.', pt: 'Assim, pois, isto não depende do que quer, nem do que corre, mas de Deus que usa de misericórdia.' },
      { v: 17, en: 'For the Scripture says to Pharaoh, “For this very purpose I caused you to be raised up, that I might show in you my power, and that my name might be proclaimed in all the earth.”', pt: 'Pois diz a Escritura a Faraó: Para isto mesmo te levantei: para em ti mostrar o meu poder, e para que seja anunciado o meu nome em toda a terra.' },
      { v: 18, en: 'So then, he has mercy on whom he desires, and he hardens whom he desires.', pt: 'Portanto, tem misericórdia de quem quer, e a quem quer endurece.' },
      { v: 19, en: 'You will say then to me, “Why does he still find fault? For who withstands his will?”', pt: 'Dir-me-ás então. Por que se queixa ele ainda? Pois, quem resiste à sua vontade?' },
      { v: 20, en: 'But indeed, O man, who are you to reply against God? Will the thing formed ask him who formed it, “Why did you make me like this?”', pt: 'Mas, ó homem, quem és tu, que a Deus replicas? Porventura a coisa formada dirá ao que a formou: Por que me fizeste assim?' },
      { v: 21, en: 'Or hasn’t the potter a right over the clay, from the same lump to make one part a vessel for honor, and another for dishonor?', pt: 'Ou não tem o oleiro poder sobre o barro, para da mesma massa fazer um vaso para uso honroso e outro para uso desonroso?' },
      { v: 22, en: 'What if God, willing to show his wrath, and to make his power known, endured with much patience vessels of wrath prepared for destruction,', pt: 'E que direis, se Deus, querendo mostrar a sua ira, e dar a conhecer o seu poder, suportou com muita paciência os vasos da ira, preparados para a perdição;' },
      { v: 23, en: 'and that he might make known the riches of his glory on vessels of mercy, which he prepared beforehand for glory,', pt: 'para que também desse a conhecer as riquezas da sua glória nos vasos de misericórdia, que de antemão preparou para a glória,' },
      { v: 24, en: 'us, whom he also called, not from the Jews only, but also from the Gentiles?', pt: 'os quais somos nós, a quem também chamou, não só dentre os judeus, mas também dentre os gentios?' },
      { v: 25, en: 'As he says also in Hosea, “I will call them ‘my people,’ which were not my people; and her ‘beloved,’ who was not beloved.”', pt: 'Como diz ele também em Oséias: Chamarei meu povo ao que não era meu povo; e amada à que não era amada.' },
      { v: 26, en: '“It will be that in the place where it was said to them, ‘You are not my people,’ There they will be called ‘children of the living God.’”', pt: 'E sucederá que no lugar em que lhes foi dito: Vós não sois meu povo; aí serão chamados filhos do Deus vivo.' },
      { v: 27, en: 'Isaiah cries concerning Israel, “If the number of the children of Israel are as the sand of the sea, it is the remnant who will be saved;', pt: 'Também Isaías exclama acerca de Israel: Ainda que o número dos filhos de Israel seja como a areia do mar, o remanescente é que será salvo.' },
      { v: 28, en: 'for He will finish the work and cut it short in righteousness, because the LORD will make a short work upon the earth.”', pt: 'Porque o Senhor executará a sua palavra sobre a terra, consumando-a e abreviando-a.' },
      { v: 29, en: 'As Isaiah has said before, “Unless the Lord of Armies had left us a seed, we would have become like Sodom, and would have been made like Gomorrah.”', pt: 'E como antes dissera Isaías: Se o Senhor dos Exércitos não nos tivesse deixado descendência, teríamos sido feitos como Sodoma, e seríamos semelhantes a Gomorra.' },
      { v: 30, en: 'What shall we say then? That the Gentiles, who didn’t follow after righteousness, attained to righteousness, even the righteousness which is of faith;', pt: 'Que diremos pois? Que os gentios, que não buscavam a justiça, alcançaram a justiça, mas a justiça que vem da fé.' },
      { v: 31, en: 'but Israel, following after a law of righteousness, didn’t arrive at the law of righteousness.', pt: 'Mas Israel, buscando a lei da justiça, não atingiu esta lei.' },
      { v: 32, en: 'Why? Because they didn’t seek it by faith, but as it were by works of the law. They stumbled over the stumbling stone;', pt: 'Por que? Porque não a buscavam pela fé, mas como que pelas obras; e tropeçaram na pedra de tropeço;' },
      { v: 33, en: 'even as it is written, “Behold, I lay in Zion a stumbling stone and a rock of offense; and no one who believes in him will be disappointed.”', pt: 'como está escrito: Eis que eu ponho em Sião uma pedra de tropeço; e uma rocha de escândalo; e quem nela crer não será confundido.' },
    ],
    10: [
      { v: 1, en: 'Brothers, my heart’s desire and my prayer to God is for Israel, that they may be saved.', pt: 'Irmãos, o bom desejo do meu coração e a minha súplica a Deus por Israel é para sua salvação.' },
      { v: 2, en: 'For I testify about them that they have a zeal for God, but not according to knowledge.', pt: 'Porque lhes dou testemunho de que têm zelo por Deus, mas não com entendimento.' },
      { v: 3, en: 'For being ignorant of God’s righteousness, and seeking to establish their own righteousness, they didn’t subject themselves to the righteousness of God.', pt: 'Porquanto, não conhecendo a justiça de Deus, e procurando estabelecer a sua própria, não se sujeitaram à justiça de Deus.' },
      { v: 4, en: 'For Christ is the fulfillment of the law for righteousness to everyone who believes.', pt: 'Pois Cristo é o fim da lei para justificar a todo aquele que crê.' },
      { v: 5, en: 'For Moses writes about the righteousness of the law, “The one who does them will live by them.”', pt: 'Porque Moisés escreve que o homem que pratica a justiça que vem da lei viverá por ela.' },
      { v: 6, en: 'But the righteousness which is of faith says this, “Don’t say in your heart, ‘Who will ascend into heaven?’ (that is, to bring Christ down);', pt: 'Mas a justiça que vem da fé diz assim: Não digas em teu coração: Quem subirá ao céu? (isto é, a trazer do alto a Cristo;)' },
      { v: 7, en: 'or, ‘Who will descend into the abyss?’ (that is, to bring Christ up from the dead.)”', pt: 'ou: Quem descerá ao abismo? (isto é, a fazer subir a Cristo dentre os mortos).' },
      { v: 8, en: 'But what does it say? “The word is near you, in your mouth, and in your heart”; that is, the word of faith, which we preach:', pt: 'Mas que diz? A palavra está perto de ti, na tua boca e no teu coração; isto é, a palavra da fé, que pregamos.' },
      { v: 9, en: 'that if you will confess with your mouth that Jesus is Lord, and believe in your heart that God raised him from the dead, you will be saved.', pt: 'Porque, se com a tua boca confessares a Jesus como Senhor, e em teu coração creres que Deus o ressuscitou dentre os mortos, será salvo;' },
      { v: 10, en: 'For with the heart, one believes unto righteousness; and with the mouth confession is made unto salvation.', pt: 'pois é com o coração que se crê para a justiça, e com a boca se faz confissão para a salvação.' },
      { v: 11, en: 'For the Scripture says, “Whoever believes in him will not be disappointed.”', pt: 'Porque a Escritura diz: Ninguém que nele crê será confundido.' },
      { v: 12, en: 'For there is no distinction between Jew and Greek; for the same Lord is Lord of all, and is rich to all who call on him.', pt: 'Porquanto não há distinção entre judeu e grego; porque o mesmo Senhor o é de todos, rico para com todos os que o invocam.' },
      { v: 13, en: 'For, “Whoever will call on the name of the Lord will be saved.”', pt: 'Porque: Todo aquele que invocar o nome do Senhor será salvo.' },
      { v: 14, en: 'How then will they call on him in whom they have not believed? How will they believe in him whom they have not heard? How will they hear without a preacher?', pt: 'Como pois invocarão aquele em quem não creram? e como crerão naquele de quem não ouviram falar? e como ouvirão, se não há quem pregue?' },
      { v: 15, en: 'And how will they preach unless they are sent? As it is written: “How beautiful are the feet of those who preach the Good News of peace, who bring glad tidings of good things!”', pt: 'E como pregarão, se não forem enviados? assim como está escrito: Quão formosos os pés dos que anunciam coisas boas!' },
      { v: 16, en: 'But they didn’t all listen to the glad news. For Isaiah says, “Lord, who has believed our report?”', pt: 'Mas nem todos deram ouvidos ao evangelho; pois Isaías diz: Senhor, quem deu crédito à nossa mensagem?' },
      { v: 17, en: 'So faith comes by hearing, and hearing by the word of God.', pt: 'Logo a fé é pelo ouvir, e o ouvir pela palavra de Cristo.' },
      { v: 18, en: 'But I say, didn’t they hear? Yes, most certainly, “Their sound went out into all the earth, their words to the ends of the world.”', pt: 'Mas pergunto: Porventura não ouviram? Sim, por certo: Por toda a terra saiu a voz deles, e as suas palavras até os confins do mundo.' },
      { v: 19, en: 'But I ask, didn’t Israel know? First Moses says, “I will provoke you to jealousy with that which is no nation, with a nation void of understanding I will make you angry.”', pt: 'Mas pergunto ainda: Porventura Israel não o soube? Primeiro diz Moisés: Eu vos porei em ciúmes com aqueles que não são povo, com um povo insensato vos provocarei à ira.' },
      { v: 20, en: 'Isaiah is very bold, and says, “I was found by those who didn’t seek me. I was revealed to those who didn’t ask for me.”', pt: 'E Isaías ousou dizer: Fui achado pelos que não me buscavam, manifestei-me aos que por mim não perguntavam.' },
      { v: 21, en: 'But as to Israel he says, “All day long I stretched out my hands to a disobedient and contrary people.”', pt: 'Quanto a Israel, porém, diz: Todo o dia estendi as minhas mãos a um povo rebelde e contradizente.' },
    ],
    11: [
      { v: 1, en: 'I ask then, did God reject his people? May it never be! For I also am an Israelite, a descendant of Abraham, of the tribe of Benjamin.', pt: 'Pergunto, pois: Acaso rejeitou Deus ao seu povo? De modo nenhum; por que eu também sou israelita, da descendência de Abraão, da tribo de Benjamim.' },
      { v: 2, en: 'God didn’t reject his people, which he foreknew. Or don’t you know what the Scripture says about Elijah? How he pleads with God against Israel:', pt: 'Deus não rejeitou ao seu povo que antes conheceu. Ou não sabeis o que a Escritura diz de Elias, como ele fala a Deus contra Israel, dizendo:' },
      { v: 3, en: '“Lord, they have killed your prophets, they have broken down your altars; and I am left alone, and they seek my life.”', pt: 'Senhor, mataram os teus profetas, e derribaram os teus altares; e só eu fiquei, e procuraram tirar-me a vida?' },
      { v: 4, en: 'But how does God answer him? “I have reserved for myself seven thousand men, who have not bowed the knee to Baal.”', pt: 'Mas que lhe diz a resposta divina? Reservei para mim sete mil varões que não dobraram os joelhos diante de Baal.' },
      { v: 5, en: 'Even so then at this present time also there is a remnant according to the election of grace.', pt: 'Assim, pois, também no tempo presente ficou um remanescente segundo a eleição da graça.' },
      { v: 6, en: 'And if by grace, then it is no longer of works; otherwise grace is no longer grace. But if it is of works, it is no longer grace; otherwise work is no longer work.', pt: 'Mas se é pela graça, já não é pelas obras; de outra maneira, a graça já não é graça.' },
      { v: 7, en: 'What then? That which Israel seeks for, that he didn’t obtain, but the chosen ones obtained it, and the rest were hardened.', pt: 'Pois quê? O que Israel busca, isso não o alcançou; mas os eleitos alcançaram; e os outros foram endurecidos,' },
      { v: 8, en: 'According as it is written, “God gave them a spirit of stupor, eyes that they should not see, and ears that they should not hear, to this very day.”', pt: 'como está escrito: Deus lhes deu um espírito entorpecido, olhos para não verem, e ouvidos para não ouvirem, até o dia de hoje.' },
      { v: 9, en: 'David says, “Let their table be made a snare, and a trap, a stumbling block, and a retribution to them.', pt: 'E Davi diz: Torne-se-lhes a sua mesa em laço, e em armadilha, e em tropeço, e em retribuição;' },
      { v: 10, en: 'Let their eyes be darkened, that they may not see. Bow down their back always.”', pt: 'escureçam-se-lhes os olhos para não verem, e tu encurva-lhes sempre as costas.' },
      { v: 11, en: 'I ask then, did they stumble that they might fall? May it never be! But by their fall salvation has come to the Gentiles, to provoke them to jealousy.', pt: 'Logo, pergunto: Porventura tropeçaram de modo que caíssem? De maneira nenhuma, antes pelo seu tropeço veio a salvação aos gentios, para os incitar à emulação.' },
      { v: 12, en: 'Now if their fall is the riches of the world, and their loss the riches of the Gentiles; how much more their fullness?', pt: 'Ora se o tropeço deles é a riqueza do mundo, e a sua diminuição a riqueza dos gentios, quanto mais a sua plenitude!' },
      { v: 13, en: 'For I speak to you who are Gentiles. Since then as I am an apostle to Gentiles, I glorify my ministry;', pt: 'Mas é a vós, gentios, que falo; e, porquanto sou apóstolo dos gentios, glorifico o meu ministério,' },
      { v: 14, en: 'if by any means I may provoke to jealousy those who are my flesh, and may save some of them.', pt: 'para ver se de algum modo posso incitar à emulação os da minha raça e salvar alguns deles.' },
      { v: 15, en: 'For if the rejection of them is the reconciling of the world, what would their acceptance be, but life from the dead?', pt: 'Porque, se a sua rejeição é a reconciliação do mundo, qual será a sua admissão, senão a vida dentre os mortos?' },
      { v: 16, en: 'If the first fruit is holy, so is the lump. If the root is holy, so are the branches.', pt: 'Se as primícias são santas, também a massa o é; e se a raiz é santa, também os ramos o são.' },
      { v: 17, en: 'But if some of the branches were broken off, and you, being a wild olive, were grafted in among them, and became partaker with them of the root and of the richness of the olive tree;', pt: 'E se alguns dos ramos foram quebrados, e tu, sendo zambujeiro, foste enxertado no lugar deles e feito participante da raiz e da seiva da oliveira,' },
      { v: 18, en: 'don’t boast over the branches. But if you boast, it is not you who support the root, but the root supports you.', pt: 'não te glories contra os ramos; e, se contra eles te gloriares, não és tu que sustentas a raiz, mas a raiz a ti.' },
      { v: 19, en: 'You will say then, “Branches were broken off, that I might be grafted in.”', pt: 'Dirás então: Os ramos foram quebrados, para que eu fosse enxertado.' },
      { v: 20, en: 'True; by their unbelief they were broken off, and you stand by your faith. Don’t be conceited, but fear;', pt: 'Está bem; pela sua incredulidade foram quebrados, e tu pela tua fé estás firme. Não te ensoberbeças, mas teme;' },
      { v: 21, en: 'for if God didn’t spare the natural branches, neither will he spare you.', pt: 'porque, se Deus não poupou os ramos naturais, não te poupará a ti.' },
      { v: 22, en: 'See then the goodness and severity of God. Toward those who fell, severity; but toward you, goodness, if you continue in his goodness; otherwise you also will be cut off.', pt: 'Considera pois a bondade e a severidade de Deus: para com os que caíram, severidade; para contigo, a bondade de Deus, se permaneceres nessa bondade; do contrário também tu serás cortado.' },
      { v: 23, en: 'They also, if they don’t continue in their unbelief, will be grafted in, for God is able to graft them in again.', pt: 'E ainda eles, se não permanecerem na incredulidade, serão enxertados; porque poderoso é Deus para os enxertar novamente.' },
      { v: 24, en: 'For if you were cut out of that which is by nature a wild olive tree, and were grafted contrary to nature into a good olive tree, how much more will these, which are the natural branches, be grafted into their own olive tree?', pt: 'Pois se tu foste cortado do natural zambujeiro, e contra a natureza enxertado em oliveira legítima, quanto mais não serão enxertados na sua própria oliveira esses que são ramos naturais!' },
      { v: 25, en: 'For I don’t desire you to be ignorant, brothers, of this mystery, so that you won’t be wise in your own conceits, that a partial hardening has happened to Israel, until the fullness of the Gentiles has come in,', pt: 'Porque não quero, irmãos, que ignoreis este mistério (para que não presumais de vós mesmos): que o endurecimento veio em parte sobre Israel, até que a plenitude dos gentios haja entrado;' },
      { v: 26, en: 'and so all Israel will be saved. Even as it is written, “There will come out of Zion the Deliverer, and he will turn away ungodliness from Jacob.', pt: 'e assim todo o Israel será salvo, como está escrito: Virá de Sião o Libertador, e desviará de Jacó as impiedades;' },
      { v: 27, en: 'This is my covenant with them, when I will take away their sins.”', pt: 'e este será o meu pacto com eles, quando eu tirar os seus pecados.' },
      { v: 28, en: 'Concerning the Good News, they are enemies for your sake. But concerning the election, they are beloved for the fathers’ sake.', pt: 'Quanto ao evangelho, eles na verdade, são inimigos por causa de vós; mas, quanto à eleição, amados por causa dos pais.' },
      { v: 29, en: 'For the gifts and the calling of God are irrevocable.', pt: 'Porque os dons e a vocação de Deus são irretratáveis.' },
      { v: 30, en: 'For as you in time past were disobedient to God, but now have obtained mercy by their disobedience,', pt: 'Pois, assim como vós outrora fostes desobedientes a Deus, mas agora alcançastes misericórdia pela desobediência deles,' },
      { v: 31, en: 'even so these also have now been disobedient, that by the mercy shown to you they may also obtain mercy.', pt: 'assim também estes agora foram desobedientes, para também alcançarem misericórdia pela misericórdia a vós demonstrada.' },
      { v: 32, en: 'For God has shut up all to disobedience, that he might have mercy on all.', pt: 'Porque Deus encerrou a todos debaixo da desobediência, a fim de usar de misericórdia para com todos.' },
      { v: 33, en: 'Oh the depth of the riches both of the wisdom and the knowledge of God! How unsearchable are his judgments, and his ways past tracing out!', pt: 'Ó profundidade das riquezas, tanto da sabedoria, como da ciência de Deus! Quão insondáveis são os seus juízos, e quão inescrutáveis os seus caminhos!' },
      { v: 34, en: '“For who has known the mind of the Lord? Or who has been his counselor?”', pt: 'Pois, quem jamais conheceu a mente do Senhor? ou quem se fez seu conselheiro?' },
      { v: 35, en: '“Or who has first given to him, and it will be repaid to him again?”', pt: 'Ou quem lhe deu primeiro a ele, para que lhe seja recompensado?' },
      { v: 36, en: 'For of him, and through him, and to him, are all things. To him be the glory for ever! Amen.', pt: 'Porque dele, e por ele, e para ele, são todas as coisas; glória, pois, a ele eternamente. Amém.' },
    ],
    12: [
      { v: 1, en: 'Therefore I urge you, brothers, by the mercies of God, to present your bodies a living sacrifice, holy, acceptable to God, which is your spiritual service.', pt: 'Rogo-vos pois, irmãos, pela compaixão de Deus, que apresenteis os vossos corpos como um sacrifício vivo, santo e agradável a Deus, que é o vosso culto racional.' },
      { v: 2, en: 'Don’t be conformed to this world, but be transformed by the renewing of your mind, so that you may prove what is the good, well-pleasing, and perfect will of God.', pt: 'E não vos conformeis a este mundo, mas transformai-vos pela renovação da vossa mente, para que experimenteis qual seja a boa, agradável, e perfeita vontade de Deus.' },
      { v: 3, en: 'For I say, through the grace that was given me, to every man who is among you, not to think of himself more highly than he ought to think; but to think reasonably, as God has apportioned to each person a measure of faith.', pt: 'Porque pela graça que me foi dada, digo a cada um dentre vós que não tenha de si mesmo mais alto conceito do que convém; mas que pense de si sobriamente, conforme a medida da fé que Deus, repartiu a cada um.' },
      { v: 4, en: 'For even as we have many members in one body, and all the members don’t have the same function,', pt: 'Pois assim como em um corpo temos muitos membros, e nem todos os membros têm a mesma função,' },
      { v: 5, en: 'so we, who are many, are one body in Christ, and individually members one of another.', pt: 'assim nós, embora muitos, somos um só corpo em Cristo, e individualmente uns dos outros.' },
      { v: 6, en: 'Having gifts differing according to the grace that was given to us, if prophecy, let us prophesy according to the proportion of our faith;', pt: 'De modo que, tendo diferentes dons segundo a graça que nos foi dada, se é profecia, seja ela segundo a medida da fé;' },
      { v: 7, en: 'or service, let us give ourselves to service; or he who teaches, to his teaching;', pt: 'se é ministério, seja em ministrar; se é ensinar, haja dedicação ao ensino;' },
      { v: 8, en: 'or he who exhorts, to his exhorting: he who gives, let him do it with generosity; he who rules, with diligence; he who shows mercy, with cheerfulness.', pt: 'ou que exorta, use esse dom em exortar; o que reparte, faça-o com liberalidade; o que preside, com zelo; o que usa de misericórdia, com alegria.' },
      { v: 9, en: 'Let love be without hypocrisy. Abhor that which is evil. Cling to that which is good.', pt: 'O amor seja não fingido. Aborrecei o mal e apegai-vos ao bem.' },
      { v: 10, en: 'In love of the brothers be tenderly affectionate to one another; in honor preferring one another;', pt: 'Amai-vos cordialmente uns aos outros com amor fraternal, preferindo-vos em honra uns aos outros;' },
      { v: 11, en: 'not lagging in diligence; fervent in spirit; serving the Lord;', pt: 'não sejais vagarosos no cuidado; sede fervorosos no espírito, servindo ao Senhor;' },
      { v: 12, en: 'rejoicing in hope; enduring in troubles; continuing steadfastly in prayer;', pt: 'alegrai-vos na esperança, sede pacientes na tribulação, perseverai na oração;' },
      { v: 13, en: 'contributing to the needs of the saints; given to hospitality.', pt: 'acudi aos santos nas suas necessidades, exercei a hospitalidade;' },
      { v: 14, en: 'Bless those who persecute you; bless, and don’t curse.', pt: 'abençoai aos que vos perseguem; abençoai, e não amaldiçoeis;' },
      { v: 15, en: 'Rejoice with those who rejoice. Weep with those who weep.', pt: 'alegrai-vos com os que se alegram; chorai com os que choram;' },
      { v: 16, en: 'Be of the same mind one toward another. Don’t set your mind on high things, but associate with the humble. Don’t be wise in your own conceits.', pt: 'sede unânimes entre vós; não ambicioneis coisas altivas mas acomodai-vos às humildes; não sejais sábios aos vossos olhos;' },
      { v: 17, en: 'Repay no one evil for evil. Respect what is honorable in the sight of all men.', pt: 'a ninguém torneis mal por mal; procurai as coisas dignas, perante todos os homens.' },
      { v: 18, en: 'If it is possible, as much as it is up to you, be at peace with all men.', pt: 'Se for possível, quanto depender de vós, tende paz com todos os homens.' },
      { v: 19, en: 'Don’t seek revenge yourselves, beloved, but give place to God’s wrath. For it is written, “Vengeance belongs to me; I will repay, says the Lord.”', pt: 'Não vos vingueis a vós mesmos, amados, mas dai lugar à ira de Deus, porque está escrito: Minha é a vingança, eu retribuirei, diz o Senhor.' },
      { v: 20, en: 'Therefore “If your enemy is hungry, feed him. If he is thirsty, give him a drink; for in doing so, you will heap coals of fire on his head.”', pt: 'Antes, se o teu inimigo tiver fome, dá-lhe de comer; se tiver sede, dá-lhe de beber; porque, fazendo isto amontoarás brasas de fogo sobre a sua cabeça.' },
      { v: 21, en: 'Don’t be overcome by evil, but overcome evil with good.', pt: 'Não te deixes vencer do mal, mas vence o mal com o bem.' },
    ],
    13: [
      { v: 1, en: 'Let every soul be in subjection to the higher authorities, for there is no authority except from God, and those who exist are ordained by God.', pt: 'Toda alma esteja sujeita às autoridades superiores; porque não há autoridade que não venha de Deus; e as que existem foram ordenadas por Deus.' },
      { v: 2, en: 'Therefore he who resists the authority, withstands the ordinance of God; and those who withstand will receive to themselves judgment.', pt: 'Por isso quem resiste à autoridade resiste à ordenação de Deus; e os que resistem trarão sobre si mesmos a condenação.' },
      { v: 3, en: 'For rulers are not a terror to the good work, but to the evil. Do you desire to have no fear of the authority? Do that which is good, and you will have praise from the same,', pt: 'Porque os magistrados não são motivo de temor para os que fazem o bem, mas para os que fazem o mal. Queres tu, pois, não temer a autoridade? Faze o bem, e terás louvor dela;' },
      { v: 4, en: 'for he is a servant of God to you for good. But if you do that which is evil, be afraid, for he doesn’t bear the sword in vain; for he is a servant of God, an avenger for wrath to him who does evil.', pt: 'porquanto ela é ministro de Deus para teu bem. Mas, se fizeres o mal, teme, pois não traz debalde a espada; porque é ministro de Deus, e vingador em ira contra aquele que pratica o mal.' },
      { v: 5, en: 'Therefore you need to be in subjection, not only because of the wrath, but also for conscience’ sake.', pt: 'Pelo que é necessário que lhe estejais sujeitos, não somente por causa da ira, mas também por causa da consciência.' },
      { v: 6, en: 'For this reason you also pay taxes, for they are servants of God’s service, attending continually on this very thing.', pt: 'Por esta razão também pagais tributo; porque são ministros de Deus, para atenderem a isso mesmo.' },
      { v: 7, en: 'Therefore give everyone what you owe: if you owe taxes, pay taxes; if customs, then customs; if respect, then respect; if honor, then honor.', pt: 'Dai a cada um o que lhe é devido: a quem tributo, tributo; a quem imposto, imposto; a quem temor, temor; a quem honra, honra.' },
      { v: 8, en: 'Owe no one anything, except to love one another; for he who loves his neighbor has fulfilled the law.', pt: 'A ninguém devais coisa alguma, senão o amor recíproco; pois quem ama ao próximo tem cumprido a lei.' },
      { v: 9, en: 'For the commandments, “You shall not commit adultery,” “You shall not murder,” “You shall not steal,” “You shall not covet,” and whatever other commandments there are, are all summed up in this saying, namely, “You shall love your neighbor as yourself.”', pt: 'Com efeito: Não adulterarás; não matarás; não furtarás; não cobiçarás; e se há algum outro mandamento, tudo nesta palavra se resume: Amarás ao teu próximo como a ti mesmo.' },
      { v: 10, en: 'Love doesn’t harm a neighbor. Love therefore is the fulfillment of the law.', pt: 'O amor não faz mal ao próximo. De modo que o amor é o cumprimento da lei.' },
      { v: 11, en: 'Do this, knowing the time, that it is already time for you to awaken out of sleep, for salvation is now nearer to us than when we first believed.', pt: 'E isso fazei, conhecendo o tempo, que já é hora de despertardes do sono; porque a nossa salvação está agora mais perto de nós do que quando nos tornamos crentes.' },
      { v: 12, en: 'The night is far gone, and the day is near. Let’s therefore throw off the deeds of darkness, and let’s put on the armor of light.', pt: 'A noite é passada, e o dia é chegado; dispamo-nos, pois, das obras das trevas, e vistamo-nos das armas da luz.' },
      { v: 13, en: 'Let us walk properly, as in the day; not in reveling and drunkenness, not in sexual promiscuity and lustful acts, and not in strife and jealousy.', pt: 'Andemos honestamente, como de dia: não em glutonarias e bebedeiras, não em impudicícias e dissoluções, não em contendas e inveja.' },
      { v: 14, en: 'But put on the Lord Jesus Christ, and make no provision for the flesh, for its lusts.', pt: 'Mas revesti-vos do Senhor Jesus Cristo; e não tenhais cuidado da carne em suas concupiscências.' },
    ],
    14: [
      { v: 1, en: 'Now accept one who is weak in faith, but not for disputes over opinions.', pt: 'Ora, ao que é fraco na fé, acolhei-o, mas não para condenar-lhe os escrúpulos.' },
      { v: 2, en: 'One man has faith to eat all things, but he who is weak eats only vegetables.', pt: 'Um crê que de tudo se pode comer, e outro, que é fraco, come só legumes.' },
      { v: 3, en: 'Don’t let him who eats despise him who doesn’t eat. Don’t let him who doesn’t eat judge him who eats, for God has accepted him.', pt: 'Quem come não despreze a quem não come; e quem não come não julgue a quem come; pois Deus o acolheu.' },
      { v: 4, en: 'Who are you who judge another’s servant? To his own lord he stands or falls. Yes, he will be made to stand, for God has power to make him stand.', pt: 'Quem és tu, que julgas o servo alheio? Para seu próprio senhor ele está em pé ou cai; mas estará firme, porque poderoso é o Senhor para o firmar.' },
      { v: 5, en: 'One man esteems one day as more important. Another esteems every day alike. Let each man be fully assured in his own mind.', pt: 'Um faz diferença entre dia e dia, mas outro julga iguais todos os dias. Cada um esteja inteiramente convicto em sua própria mente.' },
      { v: 6, en: 'He who observes the day, observes it to the Lord; and he who does not observe the day, to the Lord he does not observe it. He who eats, eats to the Lord, for he gives God thanks. He who doesn’t eat, to the Lord he doesn’t eat, and gives God thanks.', pt: 'Aquele que faz caso do dia, para o Senhor o faz. E quem come, para o Senhor come, porque dá graças a Deus; e quem não come, para o Senhor não come, e dá graças a Deus.' },
      { v: 7, en: 'For none of us lives to himself, and none dies to himself.', pt: 'Porque nenhum de nós vive para si, e nenhum morre para si.' },
      { v: 8, en: 'For if we live, we live to the Lord. Or if we die, we die to the Lord. If therefore we live or die, we are the Lord’s.', pt: 'Pois, se vivemos, para o Senhor vivemos; se morremos, para o Senhor morremos. De sorte que, quer vivamos quer morramos, somos do Senhor.' },
      { v: 9, en: 'For to this end Christ died, rose, and lived again, that he might be Lord of both the dead and the living.', pt: 'Porque foi para isto mesmo que Cristo morreu e tornou a viver, para ser Senhor tanto de mortos como de vivos.' },
      { v: 10, en: 'But you, why do you judge your brother? Or you again, why do you despise your brother? For we will all stand before the judgment seat of Christ.', pt: 'Mas tu, por que julgas teu irmão? Ou tu, também, por que desprezas teu irmão? Pois todos havemos de comparecer ante o tribunal de Deus.' },
      { v: 11, en: 'For it is written, “‘As I live,’ says the Lord, ‘to me every knee will bow. Every tongue will confess to God.’”', pt: 'Porque está escrito: Por minha vida, diz o Senhor, diante de mim se dobrará todo joelho, e toda língua louvará a Deus.' },
      { v: 12, en: 'So then each one of us will give account of himself to God.', pt: 'Assim, pois, cada um de nós dará conta de si mesmo a Deus.' },
      { v: 13, en: 'Therefore let’s not judge one another any more, but judge this rather, that no man put a stumbling block in his brother’s way, or an occasion for falling.', pt: 'Portanto não nos julguemos mais uns aos outros; antes o seja o vosso propósito não pôr tropeço ou escândalo ao vosso irmão.' },
      { v: 14, en: 'I know, and am persuaded in the Lord Jesus, that nothing is unclean of itself; except that to him who considers anything to be unclean, to him it is unclean.', pt: 'Eu sei, e estou certo no Senhor Jesus, que nada é de si mesmo imundo a não ser para aquele que assim o considera; para esse é imundo.' },
      { v: 15, en: 'Yet if because of food your brother is grieved, you walk no longer in love. Don’t destroy with your food him for whom Christ died.', pt: 'Pois, se pela tua comida se entristece teu irmão, já não andas segundo o amor. Não faças perecer por causa da tua comida aquele por quem Cristo morreu.' },
      { v: 16, en: 'Then don’t let your good be slandered,', pt: 'Não seja pois censurado o vosso bem;' },
      { v: 17, en: 'for God’s Kingdom is not eating and drinking, but righteousness, peace, and joy in the Holy Spirit.', pt: 'porque o reino de Deus não consiste no comer e no beber, mas na justiça, na paz, e na alegria no Espírito Santo.' },
      { v: 18, en: 'For he who serves Christ in these things is acceptable to God and approved by men.', pt: 'Pois quem nisso serve a Cristo agradável é a Deus e aceito aos homens.' },
      { v: 19, en: 'So then, let us follow after things which make for peace, and things by which we may build one another up.', pt: 'Assim, pois, sigamos as coisas que servem para a paz e as que contribuem para a edificação mútua.' },
      { v: 20, en: 'Don’t overthrow God’s work for food’s sake. All things indeed are clean, however it is evil for that man who creates a stumbling block by eating.', pt: 'Não destruas por causa da comida a obra de Deus. Na verdade tudo é limpo, mas é um mal para o homem dar motivo de tropeço pelo comer.' },
      { v: 21, en: 'It is good to not eat meat, drink wine, nor do anything by which your brother stumbles, is offended, or is made weak.', pt: 'Bom é não comer carne, nem beber vinho, nem fazer outra coisa em que teu irmão tropece.' },
      { v: 22, en: 'Do you have faith? Have it to yourself before God. Happy is he who doesn’t judge himself in that which he approves.', pt: 'A fé que tens, guarda-a contigo mesmo diante de Deus. Bem-aventurado aquele que não se condena a si mesmo naquilo que aprova.' },
      { v: 23, en: 'But he who doubts is condemned if he eats, because it isn’t of faith; and whatever is not of faith is sin.', pt: 'Mas aquele que tem dúvidas, se come está condenado, porque o que faz não provém da fé; e tudo o que não provém da fé é pecado.' },
      { v: 24, en: 'Now to him who is able to establish you according to my Good News and the preaching of Jesus Christ, according to the revelation of the mystery which has been kept secret through long ages,', pt: 'Now to him who is able to establish you according to my Good News and the preaching of Jesus Christ, according to the revelation of the mystery which has been kept secret through long ages,' },
      { v: 25, en: 'but now is revealed, and by the Scriptures of the prophets, according to the commandment of the eternal God, is made known for obedience of faith to all the nations;', pt: 'but now is revealed, and by the Scriptures of the prophets, according to the commandment of the eternal God, is made known for obedience of faith to all the nations;' },
      { v: 26, en: 'to the only wise God, through Jesus Christ, to whom be the glory forever! Amen.', pt: 'to the only wise God, through Jesus Christ, to whom be the glory forever! Amen.' },
    ],
    15: [
      { v: 1, en: 'Now we who are strong ought to bear the weaknesses of the weak, and not to please ourselves.', pt: 'Ora nós, que somos fortes, devemos suportar as fraquezas dos fracos, e nào agradar a nós mesmos.' },
      { v: 2, en: 'Let each one of us please his neighbor for that which is good, to be building him up.', pt: 'Portanto cada um de nós agrade ao seu próximo, visando o que é bom para edificação.' },
      { v: 3, en: 'For even Christ didn’t please himself. But, as it is written, “The reproaches of those who reproached you fell on me.”', pt: 'Porque também Cristo não se agradou a si mesmo, mas como está escrito: Sobre mim caíram as injúrias dos que te injuriavam.' },
      { v: 4, en: 'For whatever things were written before were written for our learning, that through perseverance and through encouragement of the Scriptures we might have hope.', pt: 'Porquanto, tudo que dantes foi escrito, para nosso ensino foi escrito, para que, pela constância e pela consolação provenientes das Escrituras, tenhamos esperança.' },
      { v: 5, en: 'Now the God of perseverance and of encouragement grant you to be of the same mind one with another according to Christ Jesus,', pt: 'Ora, o Deus de constância e de consolação vos dê o mesmo sentimento uns para com os outros, segundo Cristo Jesus.' },
      { v: 6, en: 'that with one accord you may with one mouth glorify the God and Father of our Lord Jesus Christ.', pt: 'Para que unânimes, e a uma boca, glorifiqueis ao Deus e Pai de nosso Senhor Jesus Cristo.' },
      { v: 7, en: 'Therefore accept one another, even as Christ also accepted you, to the glory of God.', pt: 'Portanto recebei-vos uns aos outros, como também Cristo nos recebeu, para glória de Deus.' },
      { v: 8, en: 'Now I say that Christ has been made a servant of the circumcision for the truth of God, that he might confirm the promises given to the fathers,', pt: 'Digo pois que Cristo foi feito ministro da circuncisão, por causa da verdade de Deus, para confirmar as promessas feitas aos pais;' },
      { v: 9, en: 'and that the Gentiles might glorify God for his mercy. As it is written, “Therefore will I give praise to you among the Gentiles, and sing to your name.”', pt: 'e para que os gentios glorifiquem a Deus pela sua misericórdia, como está escrito: Portanto eu te louvarei entre os gentios, e cantarei ao teu nome.' },
      { v: 10, en: 'Again he says, “Rejoice, you Gentiles, with his people.”', pt: 'E outra vez diz: Alegrai-vos, gentios, juntamente com o povo.' },
      { v: 11, en: 'Again, “Praise the Lord, all you Gentiles! Let all the peoples praise him.”', pt: 'E ainda: Louvai ao Senhor, todos os gentios, e louvem-no, todos os povos.' },
      { v: 12, en: 'Again, Isaiah says, “There will be the root of Jesse, he who arises to rule over the Gentiles; in him the Gentiles will hope.”', pt: 'E outra vez, diz também Isaías: Haverá a raiz de Jessé, aquele que se levanta para reger os gentios; nele os gentios esperarão.' },
      { v: 13, en: 'Now may the God of hope fill you with all joy and peace in believing, that you may abound in hope, in the power of the Holy Spirit.', pt: 'Ora, o Deus de esperança vos encha de todo o gozo e paz na vossa fé, para que abundeis na esperança pelo poder do Espírito Santo.' },
      { v: 14, en: 'I myself am also persuaded about you, my brothers, that you yourselves are full of goodness, filled with all knowledge, able also to admonish others.', pt: 'Eu, da minha parte, irmãos meus, estou persuadido a vosso respeito, que vós já estais cheios de bondade, cheios de todo o conhecimento e capazes, vós mesmos, de admoestar-vos uns aos outros.' },
      { v: 15, en: 'But I write the more boldly to you in part, as reminding you, because of the grace that was given to me by God,', pt: 'Mas em parte vos escrevo mais ousadamente, como para vos trazer outra vez isto à memória, por causa da graça que por Deus me foi dada,' },
      { v: 16, en: 'that I should be a servant of Christ Jesus to the Gentiles, serving as a priest of the Good News of God, that the offering up of the Gentiles might be made acceptable, sanctified by the Holy Spirit.', pt: 'para ser ministro de Cristo Jesus entre os gentios, ministrando o evangelho de Deus, para que sejam aceitáveis os gentios como oferta, santificada pelo Espírito Santo.' },
      { v: 17, en: 'I have therefore my boasting in Christ Jesus in things pertaining to God.', pt: 'Tenho, portanto, motivo para me gloriar em Cristo Jesus, nas coisas concernentes a Deus;' },
      { v: 18, en: 'For I will not dare to speak of any things except those which Christ worked through me, for the obedience of the Gentiles, by word and deed,', pt: 'porque não ousarei falar de coisa alguma senão daquilo que Cristo por meu intermédio tem feito, para obediência da parte dos gentios, por palavra e por obras,' },
      { v: 19, en: 'in the power of signs and wonders, in the power of God’s Spirit; so that from Jerusalem, and around as far as to Illyricum, I have fully preached the Good News of Christ;', pt: 'pelo poder de sinais e prodígios, no poder do Espírito Santo; de modo que desde Jerusalém e arredores, até a Ilíria, tenho divulgado o evangelho de Cristo;' },
      { v: 20, en: 'yes, making it my aim to preach the Good News, not where Christ was already named, that I might not build on another’s foundation.', pt: 'deste modo esforçando-me por anunciar o evangelho, não onde Cristo houvera sido nomeado, para não edificar sobre fundamento alheio;' },
      { v: 21, en: 'But, as it is written, “They will see, to whom no news of him came. They who haven’t heard will understand.”', pt: 'antes, como está escrito: Aqueles a quem não foi anunciado, o verão; e os que não ouviram, entenderão.' },
      { v: 22, en: 'Therefore also I was hindered these many times from coming to you,', pt: 'Pelo que também muitas vezes tenho sido impedido de ir ter convosco;' },
      { v: 23, en: 'but now, no longer having any place in these regions, and having these many years a longing to come to you,', pt: 'mas agora, não tendo mais o que me detenha nestas regiões, e tendo já há muitos anos grande desejo de ir visitar-vos,' },
      { v: 24, en: 'whenever I travel to Spain, I will come to you. For I hope to see you on my journey, and to be helped on my way there by you, if first I may enjoy your company for a while.', pt: 'eu o farei quando for à Espanha; pois espero ver-vos de passagem e por vós ser encaminhado para lá, depois de ter gozado um pouco da vossa companhia.' },
      { v: 25, en: 'But now, I say, I am going to Jerusalem, serving the saints.', pt: 'Mas agora vou a Jerusalém para ministrar aos santos.' },
      { v: 26, en: 'For it has been the good pleasure of Macedonia and Achaia to make a certain contribution for the poor among the saints who are at Jerusalem.', pt: 'Porque pareceu bem à Macedônia e à Acaia levantar uma oferta fraternal para os pobres dentre os santos que estão em Jerusalém.' },
      { v: 27, en: 'Yes, it has been their good pleasure, and they are their debtors. For if the Gentiles have been made partakers of their spiritual things, they owe it to them also to serve them in fleshly things.', pt: 'Isto pois lhes pareceu bem, como devedores que são para com eles. Porque, se os gentios foram participantes das bênçãos espirituais dos judeus, devem também servir a estes com as materiais.' },
      { v: 28, en: 'When therefore I have accomplished this, and have sealed to them this fruit, I will go on by way of you to Spain.', pt: 'Tendo, pois, concluído isto, e havendo-lhes consignado este fruto, de lá, passando por vós, irei à Espanha.' },
      { v: 29, en: 'I know that, when I come to you, I will come in the fullness of the blessing of the Good News of Christ.', pt: 'E bem sei que, quando for visitar-vos, chegarei na plenitude da bênção de Cristo.' },
      { v: 30, en: 'Now I beg you, brothers, by our Lord Jesus Christ, and by the love of the Spirit, that you strive together with me in your prayers to God for me,', pt: 'Rogo-vos, irmãos, por nosso Senhor Jesus Cristo e pelo amor do Espírito, que luteis juntamente comigo nas vossas orações por mim a Deus,' },
      { v: 31, en: 'that I may be delivered from those who are disobedient in Judea, and that my service which I have for Jerusalem may be acceptable to the saints;', pt: 'para que eu seja livre dos rebeldes que estão na Judéia, e que este meu ministério em Jerusalém seja aceitável aos santos;' },
      { v: 32, en: 'that I may come to you in joy through the will of God, and together with you, find rest.', pt: 'a fim de que, pela vontade de Deus, eu chegue até vós com alegria, e possa entre vós recobrar as forças.' },
      { v: 33, en: 'Now the God of peace be with you all. Amen.', pt: 'E o Deus de paz seja com todos vós. Amém.' },
    ],
    16: [
      { v: 1, en: 'I commend to you Phoebe, our sister, who is a servant of the assembly that is at Cenchreae,', pt: 'Recomendo-vos a nossa irmã Febe, que é serva da igreja que está em Cencréia;' },
      { v: 2, en: 'that you receive her in the Lord, in a way worthy of the saints, and that you assist her in whatever matter she may need from you, for she herself also has been a helper of many, and of my own self.', pt: 'para que a recebais no Senhor, de um modo digno dos santos, e a ajudeis em qualquer coisa que de vós necessitar; porque ela tem sido o amparo de muitos, e de mim em particular.' },
      { v: 3, en: 'Greet Prisca and Aquila, my fellow workers in Christ Jesus,', pt: 'Saudai a Prisca e a Áqüila, meus cooperadores em Cristo Jesus,' },
      { v: 4, en: 'who for my life, laid down their own necks; to whom not only I give thanks, but also all the assemblies of the Gentiles.', pt: 'os quais pela minha vida expuseram as suas cabeças; o que não só eu lhes agradeço, mas também todas as igrejas dos gentios.' },
      { v: 5, en: 'Greet the assembly that is in their house. Greet Epaenetus, my beloved, who is the first fruits of Achaia to Christ.', pt: 'Saudai também a igreja que está na casa deles. Saudai a Epêneto, meu amado, que é as primícias da Ásia para Cristo.' },
      { v: 6, en: 'Greet Mary, who labored much for us.', pt: 'Saudai a Maria, que muito trabalhou por vós.' },
      { v: 7, en: 'Greet Andronicus and Junia, my relatives and my fellow prisoners, who are notable among the apostles, who were also in Christ before me.', pt: 'Saudai a Andrônico e a Júnias, meus parentes e meus companheiros de prisão, os quais são bem conceituados entre os apóstolos, e que estavam em Cristo antes de mim.' },
      { v: 8, en: 'Greet Amplias, my beloved in the Lord.', pt: 'Saudai a Ampliato, meu amado no Senhor.' },
      { v: 9, en: 'Greet Urbanus, our fellow worker in Christ, and Stachys, my beloved.', pt: 'Saudai a Urbano, nosso cooperador em Cristo, e a Estáquis, meu amado.' },
      { v: 10, en: 'Greet Apelles, the approved in Christ. Greet those who are of the household of Aristobulus.', pt: 'Saudai a Apeles, aprovado em Cristo. Saudai aos da casa de Aristóbulo.' },
      { v: 11, en: 'Greet Herodion, my kinsman. Greet them of the household of Narcissus, who are in the Lord.', pt: 'Saudai a Herodião, meu parente. Saudai aos da casa de Narciso que estão no Senhor.' },
      { v: 12, en: 'Greet Tryphaena and Tryphosa, who labor in the Lord. Greet Persis, the beloved, who labored much in the Lord.', pt: 'Saudai a Trifena e a Trifosa, que trabalham no Senhor. Saudai a amada Pérside, que muito trabalhou no Senhor.' },
      { v: 13, en: 'Greet Rufus, the chosen in the Lord, and his mother and mine.', pt: 'Saudai a Rufo, eleito no Senhor, e a sua mãe e minha.' },
      { v: 14, en: 'Greet Asyncritus, Phlegon, Hermes, Patrobas, Hermas, and the brothers who are with them.', pt: 'Saudai a Asíncrito, a Flegonte, a Hermes, a Pátrobas, a Hermes, e aos irmãos que estão com eles.' },
      { v: 15, en: 'Greet Philologus and Julia, Nereus and his sister, and Olympas, and all the saints who are with them.', pt: 'Saudai a Filólogo e a Júlia, a Nereu e a sua irmã, e a Olimpas, e a todos os santos que com eles estão.' },
      { v: 16, en: 'Greet one another with a holy kiss. The assemblies of Christ greet you.', pt: 'Saudai-vos uns aos outros com ósculo santo. Todas as igrejas de Cristo vos saúdam.' },
      { v: 17, en: 'Now I beg you, brothers, look out for those who are causing the divisions and occasions of stumbling, contrary to the doctrine which you learned, and turn away from them.', pt: 'Rogo-vos, irmãos, que noteis os que promovem dissensões e escândalos contra a doutrina que aprendestes; desviai-vos deles.' },
      { v: 18, en: 'For those who are such don’t serve our Lord, Jesus Christ, but their own belly; and by their smooth and flattering speech, they deceive the hearts of the innocent.', pt: 'Porque os tais não servem a Cristo nosso Senhor, mas ao seu ventre; e com palavras suaves e lisonjas enganam os corações dos inocentes.' },
      { v: 19, en: 'For your obedience has become known to all. I rejoice therefore over you. But I desire to have you wise in that which is good, but innocent in that which is evil.', pt: 'Pois a vossa obediência é conhecida de todos. Comprazo-me, portanto, em vós; e quero que sejais sábios para o bem, mas simples para o mal.' },
      { v: 20, en: 'And the God of peace will quickly crush Satan under your feet. The grace of our Lord Jesus Christ be with you.', pt: 'E o Deus de paz em breve esmagará a Satanás debaixo dos vossos pés. A graça de nosso Senhor Jesus Cristo seja convosco.' },
      { v: 21, en: 'Timothy, my fellow worker, greets you, as do Lucius, Jason, and Sosipater, my relatives.', pt: 'Saúdam-vos Timóteo, meu cooperador, e Lúcio, e Jáson, e Sosípatro, meus parentes.' },
      { v: 22, en: 'I, Tertius, who write the letter, greet you in the Lord.', pt: 'Eu, Tércio, que escrevo esta carta, vos saúdo no Senhor.' },
      { v: 23, en: 'Gaius, my host and host of the whole assembly, greets you. Erastus, the treasurer of the city, greets you, as does Quartus, the brother.', pt: 'Saúda-vos Gaio, hospedeiro meu e de toda a igreja. Saúda-vos Erasto, tesoureiro da cidade, e também o irmão Quarto.' },
      { v: 24, en: 'The grace of our Lord Jesus Christ be with you all! Amen.', pt: '[A graça de nosso Senhor Jesus Cristo seja com todos vós. Amém.]' },
      { v: 25, en: 'Ora, àquele que é poderoso para vos confirmar, segundo o meu evangelho e a pregação de Jesus Cristo, conforme a revelação do mistério guardado em silêncio desde os tempos eternos,', pt: 'Ora, àquele que é poderoso para vos confirmar, segundo o meu evangelho e a pregação de Jesus Cristo, conforme a revelação do mistério guardado em silêncio desde os tempos eternos,' },
      { v: 26, en: 'mas agora manifesto e, por meio das Escrituras proféticas, segundo o mandamento do Deus, eterno, dado a conhecer a todas as nações para obediência da fé;', pt: 'mas agora manifesto e, por meio das Escrituras proféticas, segundo o mandamento do Deus, eterno, dado a conhecer a todas as nações para obediência da fé;' },
      { v: 27, en: 'ao único Deus sábio seja dada glória por Jesus Cristo para todo o sempre. Amém.', pt: 'ao único Deus sábio seja dada glória por Jesus Cristo para todo o sempre. Amém.' },
    ],
  },
};

export default book;
